/* ═══════════════════════════════════════════════════════════════
   ⏳ SISTEMA DE LOADING & SKELETON LOADERS
   ═══════════════════════════════════════════════════════════════ */

// Sistema global de loading states
const LoadingManager = {
    // Mostrar loading overlay en un contenedor específico
    show(containerId, text = 'Cargando...') {
        const container = document.getElementById(containerId);
        if (!container) return;
        
        // Verificar si ya existe overlay
        let overlay = container.querySelector('.loading-overlay');
        if (!overlay) {
            overlay = document.createElement('div');
            overlay.className = 'loading-overlay';
            overlay.innerHTML = `
                <div class="loading-spinner"></div>
                <div class="loading-text">${text}</div>
            `;
            container.style.position = 'relative';
            container.appendChild(overlay);
        }
        
        overlay.style.display = 'flex';
    },
    
    // Ocultar loading overlay
    hide(containerId) {
        const container = document.getElementById(containerId);
        if (!container) return;
        
        const overlay = container.querySelector('.loading-overlay');
        if (overlay) {
            overlay.style.opacity = '0';
            setTimeout(() => {
                overlay.style.display = 'none';
                overlay.style.opacity = '1';
            }, 200);
        }
    },
    
    // Crear skeleton loader para dashboard
    createDashboardSkeleton() {
        return `
            <div class="skeleton-metrics-grid">
                ${Array(6).fill().map(() => `
                    <div class="skeleton-metric-card">
                        <div class="skeleton skeleton-metric-icon"></div>
                        <div class="skeleton skeleton-metric-value"></div>
                        <div class="skeleton skeleton-metric-label"></div>
                    </div>
                `).join('')}
            </div>
            <div class="skeleton skeleton-chart" style="margin-bottom: 20px;"></div>
            <div class="skeleton skeleton-chart"></div>
        `;
    },
    
    // Crear skeleton loader para tabla de operaciones
    createOperationsSkeleton(rows = 10) {
        return `
            <div class="skeleton-operation-list">
                ${Array(rows).fill().map(() => `
                    <div class="skeleton-operation-item">
                        <div class="skeleton skeleton-avatar small"></div>
                        <div style="flex: 1;">
                            <div class="skeleton skeleton-text" style="width: 30%; margin-bottom: 8px;"></div>
                            <div class="skeleton skeleton-text short"></div>
                        </div>
                        <div class="skeleton skeleton-text" style="width: 80px; margin: 0;"></div>
                    </div>
                `).join('')}
            </div>
        `;
    },
    
    // Crear skeleton loader para tabla genérica
    createTableSkeleton(rows = 8, cols = 5) {
        return `
            <div class="skeleton-table">
                ${Array(rows).fill().map(() => `
                    <div class="skeleton-table-row">
                        ${Array(cols).fill().map(() => `
                            <div class="skeleton skeleton-table-cell"></div>
                        `).join('')}
                    </div>
                `).join('')}
            </div>
        `;
    },
    
    // Crear skeleton loader para cards
    createCardsSkeleton(count = 3) {
        return `
            <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 20px;">
                ${Array(count).fill().map(() => `
                    <div class="skeleton-card">
                        <div class="skeleton-card-header">
                            <div class="skeleton skeleton-avatar"></div>
                            <div style="flex: 1;">
                                <div class="skeleton skeleton-text title"></div>
                                <div class="skeleton skeleton-text short"></div>
                            </div>
                        </div>
                        <div class="skeleton skeleton-text"></div>
                        <div class="skeleton skeleton-text"></div>
                        <div class="skeleton skeleton-text medium"></div>
                    </div>
                `).join('')}
            </div>
        `;
    },
    
    // Mostrar skeleton en un contenedor
    showSkeleton(containerId, type = 'dashboard') {
        const container = document.getElementById(containerId);
        if (!container) return;
        
        let skeletonHTML = '';
        switch(type) {
            case 'dashboard':
                skeletonHTML = this.createDashboardSkeleton();
                break;
            case 'operations':
                skeletonHTML = this.createOperationsSkeleton();
                break;
            case 'table':
                skeletonHTML = this.createTableSkeleton();
                break;
            case 'cards':
                skeletonHTML = this.createCardsSkeleton();
                break;
            default:
                skeletonHTML = this.createDashboardSkeleton();
        }
        
        // Guardar contenido original
        if (!container.dataset.originalContent) {
            container.dataset.originalContent = container.innerHTML;
        }
        
        container.innerHTML = `<div class="skeleton-container">${skeletonHTML}</div>`;
    },
    
    // Ocultar skeleton y restaurar contenido
    hideSkeleton(containerId, newContent = null) {
        const container = document.getElementById(containerId);
        if (!container) return;
        
        // Si hay nuevo contenido, usarlo
        if (newContent) {
            container.innerHTML = newContent;
        } 
        // Si no, restaurar el original
        else if (container.dataset.originalContent) {
            container.innerHTML = container.dataset.originalContent;
            delete container.dataset.originalContent;
        }
        
        // Agregar animación de entrada
        container.classList.add('animate-in');
        setTimeout(() => container.classList.remove('animate-in'), 400);
    }
};

// Hacer disponible globalmente
window.LoadingManager = LoadingManager;

// Funciones helper rápidas
function showLoading(containerId, text) {
    LoadingManager.show(containerId, text);
}

function hideLoading(containerId) {
    LoadingManager.hide(containerId);
}

function showSkeleton(containerId, type) {
    LoadingManager.showSkeleton(containerId, type);
}

function hideSkeleton(containerId, newContent) {
    LoadingManager.hideSkeleton(containerId, newContent);
}

/* ═══════════════════════════════════════════════════════════════
   🎨 SISTEMA DE ANIMACIONES
   ═══════════════════════════════════════════════════════════════ */

// Agregar animaciones a elementos cuando entran al viewport
const AnimationObserver = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
        if (entry.isIntersecting) {
            entry.target.classList.add('animate-in');
        }
    });
}, {
    threshold: 0.1,
    rootMargin: '0px 0px -50px 0px'
});

// Función para animar lista con efecto stagger
function animateList(containerId, itemSelector = '.list-item') {
    const container = document.getElementById(containerId);
    if (!container) return;
    
    const items = container.querySelectorAll(itemSelector);
    items.forEach((item, index) => {
        item.classList.add('stagger-item');
        item.style.animationDelay = `${index * 0.05}s`;
    });
}

// Función para agregar animación smooth a elementos
function addSmoothAnimation(selector) {
    const elements = document.querySelectorAll(selector);
    elements.forEach(el => {
        AnimationObserver.observe(el);
    });
}

// Auto-aplicar animaciones a cards y métricas cuando se crean
document.addEventListener('DOMContentLoaded', () => {
    // Observar todas las cards y métricas para animarlas
    addSmoothAnimation('.metric-card');
    addSmoothAnimation('.platform-card');
    addSmoothAnimation('.operation-card');
    
    console.log('✨ Sistema de animaciones y loading inicializado');
});

/* ═══════════════════════════════════════════════════════════════
   FULLSCREEN INTERACTIVO PARA GRÁFICAS - MODAL CON CHART.JS
   ═══════════════════════════════════════════════════════════════ */

let _chartFullscreenInstance = null;

function openChartFullscreen(sourceCanvas) {
    const chartInstance = typeof Chart !== 'undefined' && Chart.getChart ? Chart.getChart(sourceCanvas) : null;
    if (!chartInstance) return;

    const modal = document.getElementById('chart-fullscreen-modal');
    const fullCanvas = document.getElementById('chart-fullscreen-canvas');
    const titleEl = document.getElementById('chart-fullscreen-title');
    if (!modal || !fullCanvas) return;

    // Destruir instancia previa
    if (_chartFullscreenInstance) {
        _chartFullscreenInstance.destroy();
        _chartFullscreenInstance = null;
    }

    // Título
    const dsLabel = chartInstance.data.datasets?.[0]?.label || '';
    titleEl.textContent = dsLabel || sourceCanvas.id || 'Gráfica';

    // PASO 1: Mostrar el modal PRIMERO para que el canvas tenga dimensiones reales
    modal.classList.add('active');
    document.body.style.overflow = 'hidden';

    // PASO 2: Esperar un frame para que el navegador pinte el modal y asigne dimensiones
    requestAnimationFrame(() => {
        // Fijar dimensiones explícitas al canvas según el contenedor real
        const body = fullCanvas.parentElement;
        const W = body.clientWidth || (window.innerWidth - 64);
        const H = body.clientHeight || (window.innerHeight - 80);
        fullCanvas.width  = W;
        fullCanvas.height = H;
        fullCanvas.style.width  = W + 'px';
        fullCanvas.style.height = H + 'px';

        // Clonar data directamente desde chartInstance.data (más fiable que serializar chartInstance.config)
        let clonedData;
        try {
            clonedData = JSON.parse(JSON.stringify(chartInstance.data));
        } catch (e) {
            clonedData = chartInstance.data; // fallback: referencia directa
        }

        // Clonar options (sólo las propiedades serializables)
        let opts = {};
        try {
            opts = JSON.parse(JSON.stringify(chartInstance.options));
        } catch (e) { /* usar opts vacío */ }

        // Dimensiones fijas — NO responsive para que respete los px que fijamos
        opts.responsive = false;
        opts.maintainAspectRatio = false;
        opts.animation = { duration: 300 };

        // Tooltips interactivos mejorados
        if (!opts.plugins) opts.plugins = {};
        opts.plugins.tooltip = Object.assign(opts.plugins.tooltip || {}, {
            enabled: true,
            mode: (opts.plugins.tooltip || {}).mode || 'index',
            intersect: false,
            backgroundColor: 'rgba(0,0,0,0.88)',
            titleColor: '#39ff14',
            bodyColor: '#ffffff',
            borderColor: '#39ff14',
            borderWidth: 1,
            padding: 12,
            titleFont: { size: 14, weight: 'bold' },
            bodyFont: { size: 13 }
        });

        // Leyenda visible
        if (!opts.plugins.legend) opts.plugins.legend = {};
        opts.plugins.legend.display = true;
        opts.plugins.legend.labels = Object.assign(opts.plugins.legend.labels || {}, {
            color: '#ffffff',
            font: { size: 13 },
            padding: 20
        });

        // Ejes visibles
        if (opts.scales) {
            ['x', 'y'].forEach(axis => {
                if (!opts.scales[axis]) return;
                opts.scales[axis].ticks = Object.assign(opts.scales[axis].ticks || {}, { color: '#cccccc', font: { size: 12 } });
                opts.scales[axis].grid  = Object.assign(opts.scales[axis].grid  || {}, { color: 'rgba(255,255,255,0.08)' });
            });
        }

        // Interacción
        opts.interaction = { mode: 'index', intersect: false };

        // PASO 3: Renderizar la nueva instancia con dimensiones ya disponibles
        try {
            _chartFullscreenInstance = new Chart(fullCanvas, {
                type: chartInstance.config.type,
                data: clonedData,
                options: opts
            });
        } catch (e) {
            console.error('Chart fullscreen error:', e);
            // Fallback sin clonar data
            try {
                _chartFullscreenInstance = new Chart(fullCanvas, {
                    type: chartInstance.config.type,
                    data: chartInstance.data,
                    options: opts
                });
            } catch (e2) {
                console.error('Chart fullscreen fallback error:', e2);
            }
        }
    });
}

function closeChartFullscreen() {
    const modal = document.getElementById('chart-fullscreen-modal');
    if (modal) modal.classList.remove('active');
    document.body.style.overflow = '';
    if (_chartFullscreenInstance) {
        _chartFullscreenInstance.destroy();
        _chartFullscreenInstance = null;
    }
}

function attachChartClickListener(canvas) {
    if (!canvas || canvas.dataset.fullscreenBound) return;
    canvas.dataset.fullscreenBound = '1';
    canvas.style.cursor = 'zoom-in';
    canvas.title = 'Click para pantalla completa';
    canvas.addEventListener('click', function() {
        openChartFullscreen(canvas);
    });
}

function initializeChartFullscreen() {
    setTimeout(() => {
        document.querySelectorAll('canvas').forEach(c => attachChartClickListener(c));
        console.log('📊 Fullscreen interactivo inicializado');
    }, 1200);
}

document.addEventListener('DOMContentLoaded', () => {
    initializeChartFullscreen();

    // Cerrar con ESC
    document.addEventListener('keydown', e => {
        if (e.key === 'Escape') closeChartFullscreen();
    });
});

// Detectar nuevos canvas añadidos dinámicamente
if (typeof MutationObserver !== 'undefined') {
    const _fsObserver = new MutationObserver(mutations => {
        mutations.forEach(m => m.addedNodes.forEach(node => {
            if (node.nodeType !== 1) return;
            if (node.tagName === 'CANVAS') {
                setTimeout(() => attachChartClickListener(node), 300);
            } else {
                node.querySelectorAll && node.querySelectorAll('canvas').forEach(c => {
                    setTimeout(() => attachChartClickListener(c), 300);
                });
            }
        }));
    });
    _fsObserver.observe(document.body, { childList: true, subtree: true });
}

