        // ===== SIDEBAR FUNCTIONALITY =====
        function initSidebar() {
            const sidebar = document.getElementById('sidebar');
            const sidebarToggle = document.getElementById('sidebarToggle');
            const navItems = document.querySelectorAll('.sidebar .nav-item');
            const pageTitle = document.getElementById('pageTitle');
            
            // Toggle sidebar collapse
            if (sidebarToggle) {
                sidebarToggle.addEventListener('click', () => {
                    sidebar.classList.toggle('collapsed');
                    const icon = sidebarToggle.querySelector('i');
                    const span = sidebarToggle.querySelector('span');
                    
                    if (sidebar.classList.contains('collapsed')) {
                        icon.classList.remove('fa-bars');
                        icon.classList.add('fa-arrow-right');
                        if (span) span.textContent = 'Expandir';
                    } else {
                        icon.classList.remove('fa-arrow-right');
                        icon.classList.add('fa-bars');
                        if (span) span.textContent = 'Contraer';
                    }
                    
                    // Save state in localStorage
                    localStorage.setItem('sidebarCollapsed', sidebar.classList.contains('collapsed'));
                });
            }
            
            // Restore sidebar state
            const sidebarCollapsed = localStorage.getItem('sidebarCollapsed') === 'true';
            if (sidebarCollapsed && sidebar) {
                sidebar.classList.add('collapsed');
                const icon = sidebarToggle.querySelector('i');
                const span = sidebarToggle.querySelector('span');
                if (icon) {
                    icon.classList.remove('fa-bars');
                    icon.classList.add('fa-arrow-right');
                }
                if (span) span.textContent = 'Expandir';
            }
            
            // Navigation items click
            navItems.forEach(item => {
                item.addEventListener('click', () => {
                    const target = item.dataset.target;
                    
                    if (!target) return;
                    
                    // Show section
                    showSection(target);
                    updatePageTitle(getSectionTitle(target));
                    
                    // Si es la sección de finanzas, activar tab de dashboard por defecto
                    if (target === 'finances') {
                        setTimeout(() => {
                            const tabDashboard = document.getElementById('finances-tab-dashboard');
                            const viewDashboard = document.getElementById('finances-view-dashboard');
                            if (tabDashboard && viewDashboard) {
                                // Asegurarse de que el dashboard esté visible
                                viewDashboard.classList.remove('hidden');
                                // Activar el tab de dashboard
                                tabDashboard.click();
                            }
                        }, 50);
                    }
                    
                    // Update active state
                    updateActiveNavItem(target);
                });
            });
            
            // Footer items
            const footerItems = document.querySelectorAll('.footer-item');
            footerItems.forEach(item => {
                item.addEventListener('click', () => {
                    const target = item.dataset.target;
                    if (target) {
                        showSection(target);
                        updateActiveNavItem(target);
                        updatePageTitle(getSectionTitle(target));
                        
                        // Si es la sección de finanzas, activar tab de dashboard por defecto
                        if (target === 'finances') {
                            setTimeout(() => {
                                const tabDashboard = document.getElementById('finances-tab-dashboard');
                                const viewDashboard = document.getElementById('finances-view-dashboard');
                                if (tabDashboard && viewDashboard) {
                                    // Asegurarse de que el dashboard esté visible
                                    viewDashboard.classList.remove('hidden');
                                    // Activar el tab de dashboard
                                    tabDashboard.click();
                                }
                            }, 50);
                        }
                    }
                });
            });
            
            // ─── THEME TOGGLE ──────────────────────────────────────────────
            window.applyChartTheme = function(theme) {
                if (typeof Chart === 'undefined') return;
                if (theme === 'light') {
                    Chart.defaults.color       = '#374151';
                    Chart.defaults.borderColor = '#E2E8F0';
                    if (Chart.defaults.plugins && Chart.defaults.plugins.legend)
                        Chart.defaults.plugins.legend.labels = Chart.defaults.plugins.legend.labels || {};
                    if (Chart.defaults.plugins && Chart.defaults.plugins.legend && Chart.defaults.plugins.legend.labels)
                        Chart.defaults.plugins.legend.labels.color = '#374151';
                } else {
                    Chart.defaults.color       = '#a0a0a0';
                    Chart.defaults.borderColor = '#2a2a2a';
                    if (Chart.defaults.plugins && Chart.defaults.plugins.legend)
                        Chart.defaults.plugins.legend.labels = Chart.defaults.plugins.legend.labels || {};
                    if (Chart.defaults.plugins && Chart.defaults.plugins.legend && Chart.defaults.plugins.legend.labels)
                        Chart.defaults.plugins.legend.labels.color = '#a0a0a0';
                }
            };

            function updateThemeToggleBtn(theme) {
                const toggle = document.getElementById('darkModeToggle');
                if (!toggle) return;
                if (theme === 'light') {
                    toggle.innerHTML = '<i class="fas fa-moon"></i><span>Modo Oscuro</span>';
                } else {
                    toggle.innerHTML = '<i class="fas fa-sun"></i><span>Modo Claro</span>';
                }
            }

            // Aplicar tema guardado al iniciar
            const _savedTheme = localStorage.getItem('tsTheme') || 'dark';
            if (_savedTheme === 'light') document.body.classList.add('light-mode');
            applyChartTheme(_savedTheme);
            updateThemeToggleBtn(_savedTheme);

            const darkModeToggle = document.getElementById('darkModeToggle');
            if (darkModeToggle) {
                darkModeToggle.addEventListener('click', () => {
                    // ── Paso 1: Congelar TODAS las transiciones CSS para que el cambio sea instantáneo
                    document.body.classList.add('ts-switching');

                    // ── Paso 2: Aplicar el nuevo tema
                    const isLight = document.body.classList.toggle('light-mode');
                    const newTheme = isLight ? 'light' : 'dark';

                    // ── Paso 3: Forzar reflow para que el navegador aplique los cambios antes de descongelar
                    void document.body.offsetWidth;

                    // ── Paso 4: Descongelar transiciones en el siguiente frame
                    requestAnimationFrame(() => document.body.classList.remove('ts-switching'));

                    // ── Paso 5: Persistir y actualizar UI
                    localStorage.setItem('tsTheme', newTheme);
                    applyChartTheme(newTheme);
                    updateThemeToggleBtn(newTheme);

                    // ── Paso 6: Sincronizar toggle en Configuración
                    const cfg = document.getElementById('config-theme-toggle');
                    const lbl = document.getElementById('config-theme-label');
                    const dsc = document.getElementById('config-theme-desc');
                    if (cfg) cfg.checked = isLight;
                    if (lbl) lbl.textContent = isLight ? 'Modo Claro' : 'Modo Oscuro';
                    if (dsc) dsc.textContent  = isLight ? 'Cambia al modo oscuro' : 'Activa el modo claro para una experiencia diurna';

                    // ── Paso 7: Re-pintar los charts de la sección actual con los colores del nuevo tema
                    refreshCurrentSection();
                });
            }
            
            // Support button
            const supportBtn = document.getElementById('supportBtn');
            if (supportBtn) {
                supportBtn.addEventListener('click', () => {
                    window.open('mailto:support@tradingsurvivor.com', '_blank');
                });
            }
        }
        
