        // ================================================================
        // PROFESSIONAL TRADING REPORT SYSTEM
        // openReportModal / generateProfessionalTradingReport / exportEnhancedCSV
        // ================================================================

        function openReportModal(context) {
            // Populate account selector
            const sel = document.getElementById('report-account-select');
            if (!sel) return;
            sel.innerHTML = '<option value="all">Todas las cuentas</option>';
            (DB.accounts || []).forEach(acc => {
                const opt = document.createElement('option');
                opt.value = acc.id;
                opt.textContent = acc.name;
                sel.appendChild(opt);
            });
            // Pre-select current account from context
            const ctxMap = {
                'informe': 'informe-account-select',
                'analytics': 'analytics-account-select',
                'dashboard': 'new-dashboard-account-select',
            };
            const ctxId = ctxMap[context];
            if (ctxId) {
                const ctxSel = document.getElementById(ctxId);
                if (ctxSel && ctxSel.value) sel.value = ctxSel.value;
            }
            // Default date range: this month
            setReportPeriod('month');
            // Show modal
            const modal = document.getElementById('report-modal');
            if (modal) modal.style.display = 'flex';
            // Wire radio visual feedback
            document.querySelectorAll('input[name="report-format"]').forEach(r => {
                r.removeEventListener('change', updateReportFormatUI);
                r.addEventListener('change', updateReportFormatUI);
            });
            updateReportFormatUI();
        }

        function updateReportFormatUI() {
            const pdfLbl = document.getElementById('report-fmt-pdf-lbl');
            const csvLbl = document.getElementById('report-fmt-csv-lbl');
            const pdfChk = document.getElementById('report-fmt-pdf');
            if (!pdfLbl || !csvLbl || !pdfChk) return;
            const pdfOn = pdfChk.checked;
            pdfLbl.style.border = pdfOn ? '2px solid #15803D' : '2px solid #E2E8F0';
            pdfLbl.style.background = pdfOn ? 'rgba(21,128,61,0.04)' : '#FAFAFA';
            csvLbl.style.border = !pdfOn ? '2px solid #15803D' : '2px solid #E2E8F0';
            csvLbl.style.background = !pdfOn ? 'rgba(21,128,61,0.04)' : '#FAFAFA';
        }

        function setReportPeriod(period) {
            const today = new Date();
            let from, to = today.toISOString().split('T')[0];
            switch (period) {
                case 'month':
                    from = new Date(today.getFullYear(), today.getMonth(), 1).toISOString().split('T')[0];
                    break;
                case 'quarter': {
                    const q = Math.floor(today.getMonth() / 3);
                    from = new Date(today.getFullYear(), q * 3, 1).toISOString().split('T')[0];
                    break;
                }
                case 'year':
                    from = new Date(today.getFullYear(), 0, 1).toISOString().split('T')[0];
                    break;
                case 'all':
                default: {
                    const allOps = DB.operations || [];
                    from = allOps.length > 0
                        ? allOps.reduce((min, op) => (op.date && op.date < min ? op.date : min), allOps[0].date || to)
                        : new Date(today.getFullYear() - 1, 0, 1).toISOString().split('T')[0];
                    break;
                }
            }
            const df = document.getElementById('report-date-from');
            const dt = document.getElementById('report-date-to');
            if (df) df.value = from;
            if (dt) dt.value = to;
        }

        async function executeReportDownload() {
            const accountId = document.getElementById('report-account-select').value;
            const dateFrom  = document.getElementById('report-date-from').value;
            const dateTo    = document.getElementById('report-date-to').value;
            const fmt       = (document.querySelector('input[name="report-format"]:checked') || {}).value || 'pdf';
            if (!dateFrom || !dateTo) {
                showToast(null, '⚠️ Selecciona el período del informe', 'warning');
                return;
            }
            document.getElementById('report-modal').style.display = 'none';
            if (fmt === 'csv') {
                await exportEnhancedCSV(accountId, dateFrom, dateTo);
            } else {
                await generateProfessionalTradingReport(accountId, dateFrom, dateTo);
            }
        }

        // ── Enhanced CSV ──────────────────────────────────────────────
        async function exportEnhancedCSV(accountId, dateFrom, dateTo) {
            let ops = [...(DB.operations || [])];
            if (accountId !== 'all') ops = ops.filter(op => op.accountId === accountId);
            ops = ops.filter(op => (!dateFrom || op.date >= dateFrom) && (!dateTo || op.date <= dateTo));
            ops.sort((a, b) => (a.date || '').localeCompare(b.date || ''));
            if (ops.length === 0) {
                showToast(null, '⚠️ No hay operaciones en el período seleccionado', 'warning');
                return;
            }
            const defaultCurrency = DB.settings.defaultCurrency || 'USD';
            const account = accountId !== 'all' ? DB.accounts.find(a => a.id === accountId) : null;
            const initBal = account ? account.initialBalance : (DB.accounts.reduce((s, a) => s + (a.initialBalance || 0), 0));
            const headers = [
                'Cuenta','ID','Fecha','Hora Entrada','Hora Salida','Instrumento','Tipo',
                'Entrada','Salida','Volumen','P&L Bruto','P&L Neto','Divisa',
                'Comision','Resultado','Sesion','Setup','Duracion (min)','R-Multiple',
                '% de Cuenta','P&L Acumulado','Notas'
            ];
            let cumPL = 0;
            const rows = ops.map(op => {
                const pl = parseFloat(op.pl) || 0;
                const fee = parseFloat(op.commission || op.fee || op.fees || 0);
                cumPL += pl;
                // Duration
                let durMin = '';
                if (op.entryTime && op.exitTime) {
                    try {
                        let d = (new Date('1970-01-01T' + op.exitTime) - new Date('1970-01-01T' + op.entryTime)) / 60000;
                        if (d < 0) d += 1440;
                        durMin = d.toFixed(1);
                    } catch(e) {}
                }
                // % of account
                const pctAccount = initBal > 0 ? ((pl / initBal) * 100).toFixed(3) + '%' : '';
                // R-Multiple (needs avgLoss as R unit — use 1R = 1% account as fallback)
                const rMult = initBal > 0 && initBal * 0.01 !== 0 ? (pl / (initBal * 0.01)).toFixed(2) : '';
                const esc = v => `"${String(v ?? '').replace(/"/g, '""')}"`;
                return [
                    esc(op.accountName || ''), esc(op.id || ''),
                    esc(op.date || ''), esc(op.entryTime || ''), esc(op.exitTime || ''),
                    esc((op.symbol || op.instrument || '').toUpperCase()), esc(op.type || ''),
                    op.entry || '', op.exit || '', op.volume || '',
                    pl.toFixed(2), (pl - fee).toFixed(2),
                    esc(op.currency || 'USD'), fee.toFixed(2),
                    esc(op.result || ''), esc(op.session || ''), esc(op.setup || ''),
                    durMin, rMult, pctAccount,
                    cumPL.toFixed(2), esc(op.notes || '')
                ];
            });
            const csv = [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
            const bom = '\uFEFF'; // UTF-8 BOM for Excel
            const blob = new Blob([bom + csv], { type: 'text/csv;charset=utf-8;' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url; a.download = `TradingSurvivor_Operaciones_${dateFrom}_${dateTo}.csv`;
            a.click(); URL.revokeObjectURL(url);
            showToast(null, `✅ CSV exportado: ${ops.length} operaciones`, 'success');
        }

        // ── Professional PDF Report ───────────────────────────────────
        async function generateProfessionalTradingReport(accountId, dateFrom, dateTo) {
            showLoading(true);
            try {
                // ── Filter operations ──────────────────────────────────
                let ops = [...(DB.operations || [])];
                if (accountId !== 'all') ops = ops.filter(op => op.accountId === accountId);
                ops = ops.filter(op => (!dateFrom || op.date >= dateFrom) && (!dateTo || op.date <= dateTo));
                ops.sort((a, b) => (a.date || '').localeCompare(b.date || ''));
                if (ops.length === 0) {
                    showToast(null, '⚠️ No hay operaciones en el período seleccionado', 'warning');
                    showLoading(false); return;
                }
                const account = accountId !== 'all' ? DB.accounts.find(a => a.id === accountId) : null;
                const accountName  = account ? account.name : 'Todas las cuentas';
                const currency     = account ? (account.currency || 'USD') : (DB.settings.defaultCurrency || 'USD');
                const traderName   = localStorage.getItem('username') || 'Trader';
                const fromFmt = dateFrom ? new Date(dateFrom + 'T00:00').toLocaleDateString('es-MX',{day:'2-digit',month:'short',year:'numeric'}) : 'Inicio';
                const toFmt   = dateTo   ? new Date(dateTo   + 'T00:00').toLocaleDateString('es-MX',{day:'2-digit',month:'short',year:'numeric'}) : 'Hoy';

                // ── Calculate metrics ──────────────────────────────────
                const m    = calculateMetrics(ops, accountId);
                const adv  = calculateAdvancedMetrics(ops, accountId);
                const prof = calculateProfessionalMetrics(ops, accountId);
                const xtra = calculateExtraAnalytics(ops, accountId);
                const daySt = calculateDayWinStats(ops);

                // ── Formatters ─────────────────────────────────────────
                const cv = (val, cur) => convertCurrency(val, cur || currency, currency);
                const fn = (v, d = 2) => (v === null || v === undefined || isNaN(v)) ? 'N/A' : Number(v).toFixed(d);
                const fp = (v) => (v === null || v === undefined || isNaN(v)) ? 'N/A' : fn(v, 1) + '%';
                const fc = (v) => {
                    if (v === null || v === undefined || isNaN(v)) return 'N/A';
                    const abs = Math.abs(v);
                    const sign = v < 0 ? '-' : '';
                    let s = abs >= 1e6 ? (abs/1e6).toFixed(2)+'M' : abs >= 1000 ? (abs/1000).toFixed(1)+'K' : abs.toFixed(2);
                    return sign + currency + ' ' + s;
                };

                // ── jsPDF setup ────────────────────────────────────────
                const { jsPDF } = window.jspdf;
                const doc = new jsPDF('p', 'mm', 'a4');
                const PW = 210, PH = 297, ML = 14, MR = 14;
                const CW = PW - ML - MR;

                // Color palette
                const C = {
                    navyDark:  [15,  23,  42],
                    navyMid:   [30,  41,  59],
                    navyLight: [51,  65,  85],
                    green:     [21,  128, 61],
                    greenBg:   [240, 253, 244],
                    white:     [255, 255, 255],
                    body:      [17,  24,  39],
                    secondary: [107, 114, 128],
                    tblHd:     [241, 245, 249],
                    tblAlt:    [248, 250, 252],
                    border:    [226, 232, 240],
                    red:       [220, 38,  38],
                    redBg:     [254, 242, 242],
                    amber:     [217, 119, 6],
                    divider:   [203, 213, 225],
                };

                // ── Drawing helpers ────────────────────────────────────
                const sf = (...rgb) => doc.setFillColor(...rgb);
                const st = (...rgb) => doc.setTextColor(...rgb);
                const sd = (...rgb) => doc.setDrawColor(...rgb);
                const rc = (x,y,w,h,s='F') => doc.rect(x,y,w,h,s);
                const ln = (x1,y1,x2,y2) => doc.line(x1,y1,x2,y2);
                const tx = (s,x,y,o={}) => doc.text(String(s??''),x,y,o);
                const bld = (sz=9) => { doc.setFont(undefined,'bold'); doc.setFontSize(sz); };
                const nrm = (sz=9) => { doc.setFont(undefined,'normal'); doc.setFontSize(sz); };
                const itl = (sz=9) => { doc.setFont(undefined,'italic'); doc.setFontSize(sz); };

                const addPageHeader = (title) => {
                    sf(...C.navyDark); rc(0,0,PW,9);
                    sf(...C.green);    rc(0,0,PW,2.5);
                    bld(7); st(...C.green); tx('TRADING SURVIVOR', ML, 7);
                    nrm(7); st(148,163,184); tx('· ' + title, ML + 36, 7);
                    st(148,163,184); tx('Pág. ' + doc.getCurrentPageInfo().pageNumber, PW-MR, 7, {align:'right'});
                };
                const addPageFooter = () => {
                    const fy = PH - 9;
                    sf(...C.divider); rc(ML, fy, CW, 0.3);
                    nrm(6.5); st(...C.secondary);
                    tx('Trading Survivor · Informe de Rendimiento · Confidencial', ML, fy+5);
                    tx(new Date().toLocaleDateString('es-MX',{day:'2-digit',month:'short',year:'numeric'}), PW-MR, fy+5, {align:'right'});
                };
                const newPage = (title) => {
                    doc.addPage();
                    addPageHeader(title);
                    addPageFooter();
                };
                const sectionTitle = (label, y) => {
                    bld(15); st(...C.body); tx(label, ML, y);
                    sf(...C.green); rc(ML, y+2.5, Math.min(label.length * 2.8, CW * 0.6), 1.2);
                    return y + 14;
                };

                // ================================================================
                // PAGE 1 · COVER
                // ================================================================
                // Base
                sf(...C.navyDark); rc(0,0,PW,PH);
                // Right accent panel
                sf(...C.navyMid); rc(148,0,62,PH);
                // Green side stripe
                sf(...C.green); rc(146,0,2.5,PH);
                // Top accent bar
                sf(...C.green); rc(0,0,PW,3);

                // Brand block
                bld(30); st(...C.white); tx('TRADING', ML+6, 78);
                st(...C.green);          tx('SURVIVOR', ML+6, 95);
                sf(...C.green); rc(ML+6, 99.5, 65, 1.8);

                // Report subtitle
                nrm(10); st(148,163,184); tx('INFORME DE RENDIMIENTO', ML+6, 113);

                // Divider
                sf(51,65,85); rc(ML+6, 118, 128, 0.4);

                // Trader info
                let iy = 131;
                const infoRow = (lbl, val, vs=false) => {
                    nrm(7.5); st(100,116,139); tx(lbl, ML+6, iy);
                    bld(vs ? 14 : 11); st(...C.white);
                    const maxLen = 28;
                    tx(val.length > maxLen ? val.slice(0,maxLen-1)+'…' : val, ML+6, iy+7.5);
                    iy += 19;
                };
                infoRow('TRADER', traderName, true);
                infoRow('CUENTA', accountName);
                infoRow('PERÍODO', fromFmt + ' – ' + toFmt);

                // Cover metrics strip
                sf(...C.navyMid); rc(0, PH-52, 146, 52);
                sf(51,65,85); rc(ML+6, PH-48, 128, 0.3);
                const cMetrics = [
                    { lbl:'P&L NETO',      val: fc(m.plNeto),    pos: m.plNeto >= 0 },
                    { lbl:'WIN RATE',      val: fp(m.winRate),   pos: m.winRate >= 50 },
                    { lbl:'OPERACIONES',   val: String(m.totalTrades), pos: true },
                ];
                const cmW = 128 / 3;
                cMetrics.forEach((cm,i) => {
                    const cx = ML+6 + i*cmW;
                    nrm(7); st(148,163,184); tx(cm.lbl, cx, PH-40);
                    bld(14); st(...(cm.pos ? C.green : C.red)); tx(cm.val, cx, PH-29);
                    nrm(7); st(100,116,139); tx(cm.pos ? '▲' : '▼', cx, PH-21);
                });

                // Generated date
                nrm(7); st(71,85,105); tx('Generado el ' + new Date().toLocaleDateString('es-MX',{day:'2-digit',month:'long',year:'numeric'}), ML+6, PH-13);
                // Bottom bar
                sf(...C.green); rc(0,PH-3,PW,3);

                // ================================================================
                // PAGE 2 · EXECUTIVE SUMMARY
                // ================================================================
                newPage('Resumen Ejecutivo');
                let y = 16;
                y = sectionTitle('Resumen Ejecutivo', y);

                nrm(8.5); st(...C.secondary);
                tx(ops.length + ' operaciones · ' + fromFmt + ' – ' + toFmt + ' · ' + accountName, ML, y);
                y += 9;

                // ── KPI Grid: 4 cols × 2 rows ──────────────────────────
                const kpis = [
                    { lbl:'P&L Neto',        val: fc(m.plNeto),         sub: 'Ganancia/pérdida total',           pos: m.plNeto >= 0 },
                    { lbl:'Win Rate',         val: fp(m.winRate),        sub: m.winningTrades+'W · '+m.losingTrades+'L · '+m.breakevenTrades+'B', pos: m.winRate >= 50 },
                    { lbl:'Profit Factor',    val: fn(m.profitFactor),   sub: 'Gan. bruta / Pérd. bruta',         pos: (m.profitFactor||0) >= 1.5 },
                    { lbl:'Total Trades',     val: String(m.totalTrades),sub: daySt.totalDays + ' días operados', pos: true },
                    { lbl:'Max Drawdown',     val: fp(xtra.maxDrawdownPercentage), sub: fc(xtra.maxDrawdownValue),pos: (xtra.maxDrawdownPercentage||0) < 10 },
                    { lbl:'Sharpe Ratio',     val: fn(prof.sharpeRatio), sub: 'Rend. ajust. al riesgo',          pos: (prof.sharpeRatio||0) >= 1 },
                    { lbl:'Mejor Día',        val: fc(adv.largestWinPerDay || adv.largestWin || 0), sub: 'Mayor ganancia en un día', pos: true },
                    { lbl:'Peor Día',         val: fc(adv.largestLossPerDay || adv.largestLoss || 0), sub: 'Mayor pérdida en un día', pos: false },
                ];
                const kCols=4, kW=(CW-kCols*2+2)/kCols, kH=25, kG=2.5;
                kpis.forEach((k,i) => {
                    const col=i%kCols, row=Math.floor(i/kCols);
                    const kx=ML+col*(kW+kG), ky=y+row*(kH+kG);
                    sf(...C.tblHd); rc(kx,ky,kW,kH);
                    sf(...(k.pos?C.green:C.red)); rc(kx,ky,2.5,kH);
                    nrm(7); st(...C.secondary); tx(k.lbl.toUpperCase(), kx+5, ky+6.5);
                    bld(i<4?12:11); st(...(k.pos?C.green:C.red)); tx(k.val, kx+5, ky+15.5);
                    nrm(6); st(...C.secondary); tx(k.sub, kx+5, ky+22.5);
                });
                y += 2*(kH+kG)+8;

                // ── Account overview ────────────────────────────────────
                sf(...C.divider); rc(ML,y,CW,0.4); y+=7;
                bld(11); st(...C.body); tx('Desglose de Cuenta', ML, y); y+=8;
                const infoItems = [
                    ['Balance Inicial', fc(m.initialBalance), true],
                    ['Balance Final',   fc(m.currentBalance), m.currentBalance >= m.initialBalance],
                    ['P&L Bruto',       fc(m.plBruto),        m.plBruto >= 0],
                    ['Comisiones',      fc(m.totalFees),       false],
                    ['P&L Neto',        fc(m.plNeto),          m.plNeto >= 0],
                    ['Promedio/Trade',  fc(m.avgPL),           m.avgPL >= 0],
                ];
                const iClW = CW/3;
                infoItems.forEach((it,i) => {
                    const col=i%3, row=Math.floor(i/3);
                    const ix=ML+col*iClW, iy2=y+row*14;
                    nrm(8); st(...C.secondary); tx(it[0], ix, iy2);
                    bld(9); st(...(it[2]?C.green:C.red)); tx(it[1], ix, iy2+6.5);
                });
                y += Math.ceil(infoItems.length/3)*14+8;

                // ── Win/loss distribution bar ──────────────────────────
                if (y < PH-40) {
                    sf(...C.divider); rc(ML,y,CW,0.4); y+=7;
                    bld(11); st(...C.body); tx('Distribución de Resultados', ML, y); y+=8;
                    const tot = m.totalTrades||1;
                    const wP=m.winningTrades/tot, lP=m.losingTrades/tot, bP=m.breakevenTrades/tot;
                    sf(...C.tblHd); rc(ML,y,CW,9);
                    sf(...C.green); rc(ML,y,CW*wP,9);
                    sf(...C.red);   rc(ML+CW*wP,y,CW*lP,9);
                    sf(...C.amber); rc(ML+CW*(wP+lP),y,CW*bP,9);
                    nrm(7); st(...C.white);
                    if (wP > 0.15) tx(fn(wP*100,0)+'% G', ML+2, y+6);
                    if (lP > 0.15) tx(fn(lP*100,0)+'% P', ML+CW*wP+2, y+6);
                    y+=13;
                    nrm(7.5); st(...C.body);
                    tx('Ganadoras: '+m.winningTrades+' ('+fp(m.winRate)+')', ML, y);
                    tx('Perdedoras: '+m.losingTrades+' ('+fp((m.losingTrades/tot)*100)+')', ML+65, y);
                    if (m.breakevenTrades>0) tx('Breakeven: '+m.breakevenTrades, ML+130, y);
                }

                // ================================================================
                // PAGE 3 · RISK METRICS
                // ================================================================
                newPage('Métricas de Riesgo');
                y = 16;
                y = sectionTitle('Métricas de Riesgo y Rendimiento', y);

                const rMetrics = [
                    ['Sharpe Ratio',      fn(prof.sharpeRatio),  (prof.sharpeRatio||0)>=1   ? 'Favorable (≥1.0)' : 'Mejorar (<1.0)',    (prof.sharpeRatio||0)>=1],
                    ['Sortino Ratio',     fn(prof.sortinoRatio), (prof.sortinoRatio||0)>=1  ? 'Favorable'        : 'Mejorar',            (prof.sortinoRatio||0)>=1],
                    ['Calmar Ratio',      fn(prof.calmarRatio),  (prof.calmarRatio||0)>=0.5 ? 'Aceptable'        : 'Mejorar',            (prof.calmarRatio||0)>=0.5],
                    ['Kelly Criterion',   fn(prof.kellyCriterion)+'%', 'Tamaño óptimo posición', (prof.kellyCriterion||0)>0],
                    ['Expectancy Ratio',  fn(prof.expectancyRatio), 'Expectativa por trade',  (prof.expectancyRatio||0)>0],
                    ['Consistency Score', fn(prof.consistencyScore)+'%', (prof.consistencyScore||0)>=60 ? 'Trading consistente' : 'Mejorar consistencia', (prof.consistencyScore||0)>=60],
                    ['Payoff Ratio',      fn(prof.payoffRatio),  (prof.payoffRatio||0)>=1   ? 'Relación G/P buena' : 'Relación G/P baja', (prof.payoffRatio||0)>=1],
                    ['Avg R-Multiple',    fn(prof.avgRMultiple), 'Múltiplo R promedio',      (prof.avgRMultiple||0)>0],
                    ['Max Drawdown $',    fc(xtra.maxDrawdownValue), 'Caída máxima en $',    (xtra.maxDrawdownValue||0) < 0.1*(m.initialBalance||1)],
                    ['Max Drawdown %',    fp(xtra.maxDrawdownPercentage), (xtra.maxDrawdownPercentage||0)<10 ? 'Controlado (<10%)' : 'Riesgo elevado (>10%)', (xtra.maxDrawdownPercentage||0)<10],
                    ['Racha Ganadora Máx',String(prof.maxWinStreak||adv.longestWinStreak||0)+' trades', 'Consecutivas ganadoras', true],
                    ['Racha Perdedora Máx',String(prof.maxLossStreak||adv.longestLossStreak||0)+' trades','Consecutivas perdedoras', false],
                ];
                const rmCols=2, rmCW=(CW-5)/2, rmH=17, rmG=2.2;
                rMetrics.forEach((rm,i) => {
                    const col=i%rmCols, row=Math.floor(i/rmCols);
                    const rx=ML+col*(rmCW+5), ry=y+row*(rmH+rmG);
                    sf(...C.tblHd); rc(rx,ry,rmCW,rmH);
                    sf(...(rm[3]?C.green:C.red)); rc(rx,ry,3,rmH);
                    nrm(7); st(...C.secondary); tx(rm[0], rx+5.5, ry+6);
                    bld(11); st(...(rm[3]?C.green:C.red)); tx(rm[1], rx+5.5, ry+13.5);
                    nrm(6); st(...C.secondary); tx(rm[2], rx+rmCW-2, ry+13.5, {align:'right'});
                });
                y += Math.ceil(rMetrics.length/rmCols)*(rmH+rmG)+10;

                if (y < PH-50) {
                    sf(...C.divider); rc(ML,y,CW,0.4); y+=7;
                    bld(11); st(...C.body); tx('Estadísticas de Tiempo', ML, y); y+=8;
                    const tStats=[
                        ['Días Positivos',   daySt.winningDays+' de '+daySt.totalDays, fp(daySt.dayWinRate)+' días ganadores'],
                        ['Días Negativos',   String(daySt.losingDays),                 ''],
                        ['P&L Prom./Día',    fc(adv.avgPLPerDay),                      ''],
                        ['P&L Prom./Mes',    fc(adv.avgPLPerMonth),                    ''],
                        ['Hold Promedio',    xtra.avgHoldTimeText||'N/A',              'Duración por trade'],
                        ['Std Dev P&L',      fc(xtra.stdDevPL),                        'Volatilidad de resultados'],
                    ];
                    const tsW=CW/3;
                    tStats.forEach((ts,i)=>{
                        const col=i%3, row=Math.floor(i/3);
                        const tx2=ML+col*tsW, ty=y+row*16;
                        nrm(7.5); st(...C.secondary); tx(ts[0], tx2, ty);
                        bld(9.5); st(...C.body); tx(ts[1], tx2, ty+7);
                        if(ts[2]){ nrm(6.5); st(...C.secondary); tx(ts[2], tx2, ty+12.5); }
                    });
                }

                // ================================================================
                // PAGE 4 · MONTHLY PERFORMANCE
                // ================================================================
                newPage('Rendimiento Mensual');
                y = 16;
                y = sectionTitle('Rendimiento por Mes', y);

                const monthMap = {};
                ops.forEach(op => {
                    const k = (op.date||'').substring(0,7) || 'N/A';
                    if (!monthMap[k]) monthMap[k] = [];
                    monthMap[k].push(op);
                });
                const months = Object.keys(monthMap).sort();

                const mHdrs = ['Mes','Operaciones','Ganadoras','Win Rate','P&L Bruto','Comisiones','P&L Neto'];
                const mWds  = [28,22,22,21,28,26,33];
                const drawMthHdr = () => {
                    sf(...C.navyDark); rc(ML,y,CW,8);
                    bld(7.5); st(...C.white);
                    let cx=ML+2;
                    mHdrs.forEach((h,i)=>{ tx(h,cx+1,y+5.5); cx+=mWds[i]; });
                    y+=8;
                };
                drawMthHdr();

                let mTot = {trades:0,wins:0,bruto:0,fees:0,neto:0};
                months.forEach((mon,idx)=>{
                    if(y>PH-28){ newPage('Rendimiento Mensual'); y=18; drawMthHdr(); }
                    const mOps=monthMap[mon];
                    const mWins=mOps.filter(o=>o.result==='win').length;
                    const mBruto=mOps.reduce((s,o)=>s+cv(o.pl,o.currency),0);
                    const mFees=mOps.reduce((s,o)=>s+cv(o.commission||o.fee||o.fees||0,o.currency),0);
                    const mNeto=mBruto-mFees;
                    const mWR=mOps.length>0?(mWins/mOps.length)*100:0;
                    mTot.trades+=mOps.length; mTot.wins+=mWins; mTot.bruto+=mBruto; mTot.fees+=mFees; mTot.neto+=mNeto;
                    sf(...(idx%2===0?C.white:C.tblAlt)); rc(ML,y,CW,7);
                    sf(...(mNeto>=0?C.green:C.red)); rc(ML,y,2,7);
                    let dx=ML+2;
                    const [yr,mo]=mon.split('-');
                    const mLabel=new Date(+yr,+mo-1,1).toLocaleDateString('es-MX',{month:'short',year:'numeric'});
                    bld(7.5); st(...C.body); tx(mLabel,dx+1,y+5); dx+=mWds[0];
                    nrm(7.5); st(...C.body); tx(String(mOps.length),dx+1,y+5); dx+=mWds[1];
                    tx(String(mWins),dx+1,y+5); dx+=mWds[2];
                    st(...(mWR>=50?C.green:C.red)); tx(fn(mWR)+'%',dx+1,y+5); dx+=mWds[3];
                    st(...(mBruto>=0?C.green:C.red)); tx(currency+' '+fn(mBruto),dx+1,y+5); dx+=mWds[4];
                    st(...C.red); tx(currency+' '+fn(mFees),dx+1,y+5); dx+=mWds[5];
                    bld(7.5); st(...(mNeto>=0?C.green:C.red)); tx(currency+' '+fn(mNeto),dx+1,y+5);
                    y+=7;
                });
                // Totals
                sf(...C.navyDark); rc(ML,y,CW,8);
                sf(...C.green); rc(ML,y,2,8);
                bld(7.5); st(...C.white);
                const totWR=mTot.trades>0?(mTot.wins/mTot.trades)*100:0;
                let tdx=ML+2;
                ['TOTAL',String(mTot.trades),String(mTot.wins),fn(totWR)+'%',currency+' '+fn(mTot.bruto),currency+' '+fn(mTot.fees),currency+' '+fn(mTot.neto)]
                    .forEach((v,i)=>{ tx(v,tdx+1,y+5.5); tdx+=mWds[i]; });
                y+=8;

                // ================================================================
                // PAGE 5 · INSTRUMENT ANALYSIS
                // ================================================================
                newPage('Análisis por Instrumento');
                y = 16;
                y = sectionTitle('Análisis por Instrumento', y);

                const instrMap = {};
                ops.forEach(op => {
                    const k = ((op.symbol||op.instrument||'N/A')).toUpperCase();
                    if (!instrMap[k]) instrMap[k] = [];
                    instrMap[k].push(op);
                });
                const instrList = Object.entries(instrMap).map(([sym,iops])=>{
                    const wins=iops.filter(o=>o.result==='win').length;
                    const neto=iops.reduce((s,o)=>s+cv(o.pl,o.currency),0);
                    const fees=iops.reduce((s,o)=>s+cv(o.commission||o.fee||o.fees||0,o.currency),0);
                    const gW=iops.filter(o=>o.pl>0).reduce((s,o)=>s+cv(o.pl,o.currency),0);
                    const gL=Math.abs(iops.filter(o=>o.pl<0).reduce((s,o)=>s+cv(o.pl,o.currency),0));
                    return {sym,count:iops.length,wins,wr:iops.length>0?wins/iops.length*100:0,neto,fees,pf:gL>0?gW/gL:(gW>0?99.9:0)};
                }).sort((a,b)=>b.neto-a.neto);

                const iHdrs=['Instrumento','Trades','Win Rate','Profit Factor','P&L Neto','Comisiones'];
                const iWds =[35,20,25,28,38,34];
                const drawInstrHdr = () => {
                    sf(...C.navyDark); rc(ML,y,CW,8);
                    bld(7.5); st(...C.white);
                    let ic=ML+2; iHdrs.forEach((h,i)=>{ tx(h,ic+1,y+5.5); ic+=iWds[i]; }); y+=8;
                };
                drawInstrHdr();
                instrList.forEach((instr,idx)=>{
                    if(y>PH-25){ newPage('Análisis por Instrumento'); y=18; drawInstrHdr(); }
                    sf(...(idx%2===0?C.white:C.tblAlt)); rc(ML,y,CW,7);
                    sf(...(instr.neto>=0?C.green:C.red)); rc(ML,y,2,7);
                    let id=ML+2;
                    bld(7.5); st(...C.body); tx(instr.sym.substring(0,14),id+1,y+5); id+=iWds[0];
                    nrm(7.5); st(...C.body); tx(String(instr.count),id+1,y+5); id+=iWds[1];
                    st(...(instr.wr>=50?C.green:C.red)); tx(fn(instr.wr)+'%',id+1,y+5); id+=iWds[2];
                    st(...(instr.pf>=1?C.green:C.red)); tx(fn(instr.pf,2),id+1,y+5); id+=iWds[3];
                    bld(7.5); st(...(instr.neto>=0?C.green:C.red)); tx(currency+' '+fn(instr.neto),id+1,y+5); id+=iWds[4];
                    nrm(7.5); st(...C.secondary); tx(currency+' '+fn(instr.fees),id+1,y+5);
                    y+=7;
                });

                // ================================================================
                // PAGE 6 · BEST & WORST TRADES
                // ================================================================
                newPage('Mejores y Peores Trades');
                y = 16;
                y = sectionTitle('Top 10 Mejores y Peores Trades', y);

                const sortedByPL = [...ops].sort((a,b)=>cv(b.pl,b.currency)-cv(a.pl,a.currency));
                const topTrades   = sortedByPL.slice(0,10);
                const worstTrades = sortedByPL.slice(-10).reverse();

                const tHdrs=['Fecha','Instrumento','Tipo','Entrada','Salida','Vol.','P&L Neto'];
                const tWds =[22,32,15,22,22,15,32];

                const drawTradeTable = (label, trades, isGood) => {
                    if(y+10>PH-25){ newPage('Mejores y Peores Trades'); y=18; }
                    sf(...(isGood?C.greenBg:C.redBg)); rc(ML,y,CW,7);
                    sf(...(isGood?C.green:C.red)); rc(ML,y,3,7);
                    bld(9); st(...(isGood?C.green:C.red)); tx(label,ML+6,y+5); y+=7;
                    sf(...C.navyDark); rc(ML,y,CW,7);
                    bld(7); st(...C.white);
                    let tc=ML+2; tHdrs.forEach((h,i)=>{ tx(h,tc+1,y+5); tc+=tWds[i]; }); y+=7;
                    trades.forEach((trade,idx)=>{
                        if(y>PH-20) return;
                        const pl=cv(trade.pl,trade.currency);
                        sf(...(idx%2===0?C.white:C.tblAlt)); rc(ML,y,CW,6.5);
                        sf(...(pl>=0?C.green:C.red)); rc(ML,y,2,6.5);
                        let td=ML+2;
                        nrm(7); st(...C.body); tx(trade.date||'',td+1,y+4.5); td+=tWds[0];
                        bld(7); tx(((trade.symbol||trade.instrument||'').substring(0,14)).toUpperCase(),td+1,y+4.5); td+=tWds[1];
                        nrm(7); st(...(trade.type==='long'?C.green:C.red)); tx((trade.type||'').toUpperCase(),td+1,y+4.5); td+=tWds[2];
                        st(...C.body); tx(fn(trade.entry||0,4),td+1,y+4.5); td+=tWds[3];
                        tx(fn(trade.exit||0,4),td+1,y+4.5); td+=tWds[4];
                        tx(fn(trade.volume||0,2),td+1,y+4.5); td+=tWds[5];
                        bld(7.5); st(...(pl>=0?C.green:C.red)); tx(currency+' '+fn(pl,2),td+1,y+4.5);
                        y+=6.5;
                    });
                    y+=5;
                };
                drawTradeTable('🏆  TOP 10 MEJORES TRADES', topTrades, true);
                if(y+85>PH-25){ newPage('Mejores y Peores Trades'); y=18; }
                drawTradeTable('⚠️  TOP 10 PEORES TRADES', worstTrades, false);

                // ================================================================
                // PAGE 7+ · FULL OPERATIONS LOG
                // ================================================================
                newPage('Historial de Operaciones');
                y = 16;
                y = sectionTitle('Historial Completo de Operaciones', y);
                nrm(8); st(...C.secondary);
                tx(ops.length+' operaciones · ordenadas cronológicamente', ML, y); y+=9;

                const fHdrs=['Fecha','Instrumento','Tipo','Entrada','Salida','Vol.','P&L','Comis.','Result.'];
                const fWds =[22,28,14,20,20,14,28,20,20];
                const drawFullHdr = () => {
                    sf(...C.navyDark); rc(ML,y,CW,7);
                    bld(7); st(...C.white);
                    let fc3=ML+2; fHdrs.forEach((h,i)=>{ tx(h,fc3+1,y+5); fc3+=fWds[i]; }); y+=7;
                };
                drawFullHdr();
                let cumPL2=0;
                ops.forEach((op,idx)=>{
                    if(y>PH-20){ newPage('Historial de Operaciones'); y=18; drawFullHdr(); }
                    const pl=cv(op.pl,op.currency);
                    const fee=cv(op.commission||op.fee||op.fees||0,op.currency);
                    cumPL2+=pl;
                    sf(...(idx%2===0?C.white:C.tblAlt)); rc(ML,y,CW,6.5);
                    sf(...(pl>=0?C.green:C.red)); rc(ML,y,2,6.5);
                    let fd=ML+2;
                    nrm(7); st(...C.body); tx(op.date||'',fd+1,y+4.5); fd+=fWds[0];
                    bld(7); tx(((op.symbol||op.instrument||'').substring(0,13)).toUpperCase(),fd+1,y+4.5); fd+=fWds[1];
                    nrm(7); st(...(op.type==='long'?C.green:C.red)); tx((op.type||'').toUpperCase(),fd+1,y+4.5); fd+=fWds[2];
                    st(...C.body); tx(fn(op.entry||0,4),fd+1,y+4.5); fd+=fWds[3];
                    tx(fn(op.exit||0,4),fd+1,y+4.5); fd+=fWds[4];
                    tx(fn(op.volume||0,2),fd+1,y+4.5); fd+=fWds[5];
                    bld(7.5); st(...(pl>=0?C.green:C.red)); tx(fn(pl,2),fd+1,y+4.5); fd+=fWds[6];
                    nrm(7); st(...C.secondary); tx(fn(fee,2),fd+1,y+4.5); fd+=fWds[7];
                    const res=op.result||(pl>0?'WIN':pl<0?'LOSS':'BE');
                    st(...(res.toLowerCase()==='win'?C.green:res.toLowerCase()==='loss'?C.red:C.amber));
                    bld(7); tx(res.toUpperCase().substring(0,4),fd+1,y+4.5);
                    y+=6.5;
                });

                // ── Save ──────────────────────────────────────────────────────
                const fileName = `TradingSurvivor_Informe_${dateFrom}_${dateTo}.pdf`;
                doc.save(fileName);
                showLoading(false);
                showToast(null, `✅ Informe generado — ${doc.getNumberOfPages()} páginas · ${ops.length} operaciones`, 'success');

            } catch(err) {
                console.error('❌ Error generando informe profesional:', err);
                showLoading(false);
                showToast(null, '❌ Error al generar informe: ' + err.message, 'error');
            }
        }
        // ── END PROFESSIONAL REPORT SYSTEM ───────────────────────────────

        async function downloadSectionPDF(sectionId, sectionName) {
            const section = document.getElementById(sectionId);
            if (!section) {
                console.error('Sección no encontrada:', sectionId);
                alert('Error: No se encontró la sección para exportar.');
                return;
            }

            try {
                // Mostrar loading
                showLoading(true);

                // Crear overlay para ocultar el proceso visualmente
                const overlay = document.createElement('div');
                overlay.style.position = 'fixed';
                overlay.style.top = '0';
                overlay.style.left = '0';
                overlay.style.width = '100%';
                overlay.style.height = '100%';
                overlay.style.background = 'rgba(0, 0, 0, 0.9)';
                overlay.style.zIndex = '99999';
                overlay.style.display = 'flex';
                overlay.style.alignItems = 'center';
                overlay.style.justifyContent = 'center';
                overlay.innerHTML = '<div style="color: #39ff14; font-size: 20px; font-weight: bold;">Generando PDF...</div>';
                document.body.appendChild(overlay);

                // Scroll to top of section
                section.scrollIntoView({ behavior: 'instant', block: 'start' });
                
                // Esperar que el scroll se complete y los gráficos se rendericen
                await new Promise(resolve => setTimeout(resolve, 500));

                // Capturar la sección original directamente (no clonar)
                const canvas = await html2canvas(section, {
                    backgroundColor: '#0a0a0a',
                    scale: 2,
                    logging: false,
                    useCORS: true,
                    allowTaint: true,
                    foreignObjectRendering: false,
                    imageTimeout: 0,
                    windowWidth: section.scrollWidth,
                    windowHeight: section.scrollHeight,
                    onclone: (clonedDoc) => {
                        // Asegurar que los canvas de Chart.js se copien correctamente
                        const originalCanvases = section.querySelectorAll('canvas');
                        const clonedCanvases = clonedDoc.querySelectorAll('canvas');
                        
                        originalCanvases.forEach((originalCanvas, index) => {
                            if (clonedCanvases[index]) {
                                const ctx = clonedCanvases[index].getContext('2d');
                                clonedCanvases[index].width = originalCanvas.width;
                                clonedCanvases[index].height = originalCanvas.height;
                                ctx.drawImage(originalCanvas, 0, 0);
                            }
                        });
                    }
                });

                // Verificar que el canvas tenga contenido
                if (canvas.width === 0 || canvas.height === 0) {
                    throw new Error('El canvas generado está vacío');
                }

                // Remover overlay
                document.body.removeChild(overlay);

                // Crear PDF con jsPDF
                const { jsPDF } = window.jspdf;
                const imgWidth = 210; // A4 width in mm
                const pageHeight = 297; // A4 height in mm
                const imgHeight = (canvas.height * imgWidth) / canvas.width;
                
                const pdf = new jsPDF('p', 'mm', 'a4');
                
                // Agregar header en primera página
                pdf.setFillColor(10, 10, 10);
                pdf.rect(0, 0, 210, 297, 'F');
                
                pdf.setTextColor(57, 255, 20);
                pdf.setFontSize(24);
                pdf.setFont(undefined, 'bold');
                pdf.text('TRADING SURVIVOR', 105, 20, { align: 'center' });
                
                pdf.setFontSize(14);
                pdf.setFont(undefined, 'normal');
                pdf.setTextColor(160, 160, 160);
                pdf.text(sectionName, 105, 30, { align: 'center' });
                pdf.text(new Date().toLocaleDateString('es-ES', { year: 'numeric', month: 'long', day: 'numeric' }), 105, 37, { align: 'center' });
                
                // Línea separadora
                pdf.setDrawColor(57, 255, 20);
                pdf.setLineWidth(0.5);
                pdf.line(20, 40, 190, 40);
                
                // Agregar la imagen capturada
                const imgData = canvas.toDataURL('image/png', 1.0);
                
                let heightLeft = imgHeight;
                let position = 45;
                
                // Primera página - agregar imagen debajo del header
                const firstPageHeight = Math.min(imgHeight, pageHeight - position);
                pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
                heightLeft -= (pageHeight - position);
                
                // Páginas adicionales si es necesario
                while (heightLeft > 0) {
                    position = heightLeft - imgHeight;
                    pdf.addPage();
                    pdf.setFillColor(10, 10, 10);
                    pdf.rect(0, 0, 210, 297, 'F');
                    pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
                    heightLeft -= pageHeight;
                }

                // Descargar PDF
                const fileName = `TradingSurvivor_${sectionName}_${new Date().toISOString().split('T')[0]}.pdf`;
                pdf.save(fileName);
                
                showLoading(false);
                
                // Mostrar mensaje de éxito
                showMessage('✅ PDF descargado correctamente', 'success');
                
            } catch (error) {
                console.error('Error al generar PDF:', error);
                showLoading(false);
                // Limpiar en caso de error
                const overlay = document.querySelector('div[style*="z-index: 99999"]');
                if (overlay && overlay.parentNode) {
                    document.body.removeChild(overlay);
                }
                alert('Error al generar el PDF: ' + error.message + '\n\nPor favor, intenta nuevamente o usa Ctrl+P para imprimir la página.');
            }
        }

