        function calculateStatsFromTrades(trades) {
            const stats = {
                totalTrades: trades.length,
                totalWins: 0,
                totalLosses: 0,
                totalBreakeven: 0,
                totalWinPL: 0,
                totalLossPL: 0,
                largestWin: 0,
                largestLoss: 0,
                rrValues: [],
                winDurations: [],
                lossDurations: []
            };
            
            trades.forEach(trade => {
                const pl = parseFloat(trade.pl) || 0;
                
                if (pl > 0) {
                    stats.totalWins++;
                    stats.totalWinPL += pl;
                    if (pl > stats.largestWin) stats.largestWin = pl;
                    
                    // Calcular duración si existe
                    if (trade.entryTime && trade.exitTime) {
                        try {
                            const entry = new Date(`${trade.date} ${trade.entryTime}`);
                            const exit = new Date(`${trade.date} ${trade.exitTime}`);
                            const duration = (exit - entry) / (1000 * 60); // minutos
                            if (duration > 0) stats.winDurations.push(duration);
                        } catch (e) {}
                    }
                } else if (pl < 0) {
                    stats.totalLosses++;
                    stats.totalLossPL += Math.abs(pl);
                    if (pl < stats.largestLoss) stats.largestLoss = pl;
                    
                    // Calcular duración si existe
                    if (trade.entryTime && trade.exitTime) {
                        try {
                            const entry = new Date(`${trade.date} ${trade.entryTime}`);
                            const exit = new Date(`${trade.date} ${trade.exitTime}`);
                            const duration = (exit - entry) / (1000 * 60); // minutos
                            if (duration > 0) stats.lossDurations.push(duration);
                        } catch (e) {}
                    }
                } else {
                    stats.totalBreakeven++;
                }
                
                // R:R si existe
                if (trade.rr && trade.rr > 0) {
                    stats.rrValues.push(trade.rr);
                }
            });
            
            console.log('📊 Stats calculados:', stats);
            return stats;
        }
        
