        document.addEventListener('DOMContentLoaded', initializeOperationDetailTabs);

// ===== SUPABASE AUTHENTICATION SYSTEM =====

// Variable global para el cliente Supabase
var supabase = null;

// Función para inicializar Supabase esperando al evento si es necesario
async function initializeSupabase() {
    // Si ya está disponible, usarlo inmediatamente
    if (window.supabase && window.supabase.auth) {
        console.log('✅ Supabase ya disponible inmediatamente');
        supabase = window.supabase;
        return true;
    }
    
    // Esperar al evento 'supabase-ready' con timeout más largo
    console.log('⏳ Esperando inicialización de Supabase...');
    return new Promise((resolve) => {
        let resolved = false;
        
        const checkSupabase = () => {
            if (resolved) return;
            
            if (window.supabase && window.supabase.auth) {
                resolved = true;
                console.log('✅ Supabase inicializado correctamente');
                console.log('✅ Supabase.auth disponible:', typeof window.supabase.auth);
                supabase = window.supabase;
                resolve(true);
            } else {
                console.warn('⚠️ Supabase cargado pero auth no disponible');
                resolved = true;
                resolve(false);
            }
        };
        
        // Intentar primero de forma síncrona
        if (window.supabaseReady || (window.supabase && window.supabase.auth)) {
            checkSupabase();
        } else {
            // Si no está listo, esperar al evento con timeout de 10 segundos
            window.addEventListener('supabase-ready', checkSupabase, { once: true });
            
            // Timeout de 10 segundos
            setTimeout(() => {
                if (!resolved) {
                    resolved = true;
                    console.error('⏰ Timeout esperando Supabase (10s)');
                    // Intentar una vez más antes de fallar
                    if (window.supabase && window.supabase.auth) {
                        console.log('✅ Supabase disponible en timeout');
                        supabase = window.supabase;
                        resolve(true);
                    } else {
                        resolve(false);
                    }
                }
            }, 10000);
        }
    });
}

// Inicializar sin bloquear
initializeSupabase().catch(err => console.warn('⚠️ Init Supabase:', err));

// Función para verificar permisos RLS
async function testRLSPermissions() {
    if (!currentUser) {
        alert('❌ No hay usuario logueado');
        return;
    }

    try {
        console.log('🛡️ Testing RLS permissions...');
        console.log('👤 Current user ID:', currentUser.id);

        // Test 1: Probar SELECT en accounts
        console.log('🔍 Testing SELECT on accounts...');
        const { data: selectData, error: selectError } = await supabase
            .from('accounts')
            .select('*')
            .eq('user_id', currentUser.id);

        if (selectError) {
            console.error('❌ SELECT test failed:', selectError);
            alert(`❌ Error en SELECT: ${selectError.message}`);
            return;
        }

        console.log('✅ SELECT test passed:', selectData);

        // Test 2: Probar INSERT en accounts
        console.log('🔍 Testing INSERT on accounts...');
        const testAccount = {
            id: 'test_' + Date.now(),
            user_id: currentUser.id,
            name: 'Test Account',
            currency: 'USD',
            platform: 'test',
            initial_balance: 1000,
            balance: 1000
        };

        const { data: insertData, error: insertError } = await supabase
            .from('accounts')
            .insert(testAccount)
            .select();

        if (insertError) {
            console.error('❌ INSERT test failed:', insertError);
            alert(`❌ Error en INSERT: ${insertError.message}`);
            return;
        }

        console.log('✅ INSERT test passed:', insertData);

        // Test 3: Limpiar - eliminar el registro de prueba
        await supabase
            .from('accounts')
            .delete()
            .eq('id', testAccount.id);

        console.log('✅ Test cleanup completed');
        alert('✅ Todos los permisos RLS funcionan correctamente!');

    } catch (error) {
        console.error('❌ RLS test error:', error);
        alert(`❌ Error en prueba RLS: ${error.message}`);
    }
}
