// ===== LAZY LOADING: Cargar imágenes solo cuando se abre el detalle =====
window.loadOperationImages = async function(operationId) {
    if (!currentUser) return [];

    try {
        console.log(`🔄 Cargando imágenes para operación ${operationId}...`);
        
        const { data, error } = await supabase
            .from('operations')
            .select('image_datas')
            .eq('id', operationId)
            .eq('user_id', currentUser.id)
            .single();

        if (error) {
            console.error('Error cargando imágenes:', error);
            return [];
        }

        // Procesar image_datas: convertir strings JSON a objetos
        let imageDatas = [];
        if (data && data.image_datas && Array.isArray(data.image_datas)) {
            imageDatas = data.image_datas.map(imgData => {
                if (typeof imgData === 'string') {
                    try {
                        return JSON.parse(imgData);
                    } catch (e) {
                        return imgData;
                    }
                }
                return imgData;
            });
        }

        console.log(`✅ ${imageDatas.length} imágenes cargadas para operación ${operationId}`);
        return imageDatas;
    } catch (error) {
        console.error('Error loading operation images:', error);
        return [];
    }
}

// ===== CARGAR IMÁGENES PARA CHARTBOOK (últimos 6 meses con imágenes) =====
window.loadChartbookOperationsImages = async function() {
    if (!currentUser) {
        console.warn('⚠️ [loadChartbookOperationsImages] No hay usuario autenticado');
        return;
    }

    try {
        console.log('🖼️ [Chartbook] Cargando imágenes de operaciones...');
        
        // Obtener IDs de operaciones actuales en DB que no tienen imágenes cargadas
        const operationsNeedingImages = DB.operations
            .filter(op => !op.imageDatas || op.imageDatas.length === 0)
            .map(op => op.id);
        
        if (operationsNeedingImages.length === 0) {
            console.log('✅ [Chartbook] Todas las operaciones ya tienen imágenes cargadas');
            return;
        }

        console.log(`🔍 [Chartbook] Consultando imágenes para ${operationsNeedingImages.length} operaciones...`);
        
        // Cargar solo las operaciones con imágenes (array no vacío)
        const { data, error } = await supabase
            .from('operations')
            .select('id, image_datas')
            .eq('user_id', currentUser.id)
            .in('id', operationsNeedingImages)
            .not('image_datas', 'is', null);

        if (error) {
            console.error('❌ [Chartbook] Error cargando imágenes:', error);
            return;
        }

        console.log(`📸 [Chartbook] ${data?.length || 0} operaciones con imágenes encontradas`);

        // Actualizar operaciones en DB con sus imágenes
        if (data && data.length > 0) {
            data.forEach(opWithImages => {
                const opIndex = DB.operations.findIndex(op => op.id === opWithImages.id);
                if (opIndex !== -1 && opWithImages.image_datas) {
                    // Procesar image_datas: convertir strings JSON a objetos
                    const imageDatas = opWithImages.image_datas.map(imgData => {
                        if (typeof imgData === 'string') {
                            try {
                                return JSON.parse(imgData);
                            } catch (e) {
                                return imgData;
                            }
                        }
                        return imgData;
                    });
                    DB.operations[opIndex].imageDatas = imageDatas;
                }
            });
            console.log(`✅ [Chartbook] ${data.length} operaciones actualizadas con imágenes`);
        }
    } catch (error) {
        console.error('❌ [Chartbook] Error en loadChartbookOperationsImages:', error);
    }
}

