// ============================================
// BYBIT API CLASS (V5)
// ============================================
class BybitAPI {
    constructor(apiKey, secretKey) {
        this.apiKey = apiKey;
        this.secretKey = secretKey;
        const isProduction = window.location.hostname !== 'localhost' && window.location.hostname !== '127.0.0.1';
        this.proxyURL = isProduction ? `${window.location.origin}/api` : 'http://127.0.0.1:8003';
        console.log('🔗 Bybit API inicializada');
    }

    async makeRequest(endpoint, params = {}) {
        const queryString = new URLSearchParams(params).toString();
        const url = `${this.proxyURL}/bybit${endpoint}${queryString ? '?' + queryString : ''}`;
        const response = await fetch(url, {
            headers: { 'x-api-key': this.apiKey, 'x-secret-key': this.secretKey, 'Content-Type': 'application/json' }
        });
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        const data = await response.json();
        if (data.retCode !== undefined && data.retCode !== 0) throw new Error(`Bybit Error ${data.retCode}: ${data.retMsg}`);
        return data;
    }

    async testConnection() {
        const result = await this.makeRequest('/v5/account/wallet-balance', { accountType: 'UNIFIED' });
        return result;
    }

    async getTradeHistory(category = 'linear') {
        const allTrades = [];
        const totalMs = 180 * 24 * 60 * 60 * 1000;
        let cursor = null;
        const startTime = Date.now() - totalMs;
        console.log('📈 Obteniendo historial Bybit...');
        for (let i = 0; i < 20; i++) {
            const params = { category, limit: 100, startTime };
            if (cursor) params.cursor = cursor;
            try {
                const result = await this.makeRequest('/v5/execution/list', params);
                const trades = result.result?.list || [];
                allTrades.push(...trades);
                cursor = result.result?.nextPageCursor;
                if (!cursor || trades.length === 0) break;
            } catch (error) {
                console.warn('Bybit pagination error:', error.message);
                break;
            }
        }
        console.log(`📊 Bybit: ${allTrades.length} trades`);
        return allTrades;
    }
}

// ============================================
// BINANCE FUTURES API CLASS (fapi)
// ============================================
class BinanceFuturesAPI {
    constructor(apiKey, secretKey) {
        this.apiKey = apiKey;
        this.secretKey = secretKey;
        const isProduction = window.location.hostname !== 'localhost' && window.location.hostname !== '127.0.0.1';
        this.proxyURL = isProduction ? `${window.location.origin}/api` : 'http://127.0.0.1:8003';
        console.log('🔗 Binance Futures API inicializada');
    }

    async makeRequest(endpoint, params = {}) {
        const queryString = new URLSearchParams(params).toString();
        const url = `${this.proxyURL}/binance${endpoint}${queryString ? '?' + queryString : ''}`;
        const response = await fetch(url, {
            headers: { 'x-api-key': this.apiKey, 'x-secret-key': this.secretKey, 'Content-Type': 'application/json' }
        });
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        const data = await response.json();
        if (data.code && data.code < 0) throw new Error(`Binance Error ${data.code}: ${data.msg}`);
        return data;
    }

    async testConnection() {
        return await this.makeRequest('/fapi/v2/account');
    }

    async getTradeHistory(symbol = '') {
        const allTrades = [];
        const windowMs = 7 * 24 * 60 * 60 * 1000;
        const totalMs = 90 * 24 * 60 * 60 * 1000;
        const endTime = Date.now();
        let winEnd = endTime;
        let winStart = Math.max(winEnd - windowMs, endTime - totalMs);
        console.log('📈 Obteniendo historial Binance Futures...');
        while (winEnd > endTime - totalMs && allTrades.length < 5000) {
            const params = { startTime: winStart, endTime: winEnd, limit: 1000 };
            if (symbol) params.symbol = symbol;
            try {
                const trades = await this.makeRequest('/fapi/v1/userTrades', params);
                if (Array.isArray(trades) && trades.length > 0) allTrades.push(...trades);
                else break;
            } catch (e) { console.warn('Binance window error:', e.message); break; }
            winEnd = winStart;
            winStart = Math.max(winEnd - windowMs, endTime - totalMs);
        }
        console.log(`📊 Binance: ${allTrades.length} trades`);
        return allTrades;
    }
}

// ============================================
// OKX API CLASS (V5)
// ============================================
class OKXAPI {
    constructor(apiKey, secretKey, passphrase) {
        this.apiKey = apiKey;
        this.secretKey = secretKey;
        this.passphrase = passphrase;
        const isProduction = window.location.hostname !== 'localhost' && window.location.hostname !== '127.0.0.1';
        this.proxyURL = isProduction ? `${window.location.origin}/api` : 'http://127.0.0.1:8003';
        console.log('🔗 OKX API inicializada');
    }

    async makeRequest(endpoint, params = {}) {
        const queryString = new URLSearchParams(params).toString();
        const url = `${this.proxyURL}/okx${endpoint}${queryString ? '?' + queryString : ''}`;
        const response = await fetch(url, {
            headers: { 'x-api-key': this.apiKey, 'x-secret-key': this.secretKey, 'x-passphrase': this.passphrase, 'Content-Type': 'application/json' }
        });
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        const data = await response.json();
        if (data.code && data.code !== '0') throw new Error(`OKX Error ${data.code}: ${data.msg}`);
        return data;
    }

    async testConnection() {
        return await this.makeRequest('/api/v5/account/balance');
    }

    async getTradeHistory(instType = 'SWAP') {
        const allTrades = [];
        let after = '';
        console.log('📈 Obteniendo historial OKX...');
        for (let i = 0; i < 20; i++) {
            const params = { instType, limit: '100' };
            if (after) params.after = after;
            try {
                const result = await this.makeRequest('/api/v5/trade/fills-history', params);
                const trades = result.data || [];
                allTrades.push(...trades);
                if (trades.length < 100) break;
                after = trades[trades.length - 1].billId;
            } catch (e) { console.warn('OKX error:', e.message); break; }
        }
        console.log(`📊 OKX: ${allTrades.length} trades`);
        return allTrades;
    }
}

