// GATE.IO FUTURES API CLASS (V4)
// ============================================
class GateAPI {
    constructor(apiKey, secretKey) {
        this.apiKey = apiKey;
        this.secretKey = secretKey;
        const isProduction = window.location.hostname !== 'localhost' && window.location.hostname !== '127.0.0.1';
        this.proxyURL = isProduction ? `${window.location.origin}/api` : 'http://127.0.0.1:8003';
        console.log('🔗 Gate.io API inicializada');
    }

    async makeRequest(endpoint, params = {}) {
        const queryString = new URLSearchParams(params).toString();
        const url = `${this.proxyURL}/gate${endpoint}${queryString ? '?' + queryString : ''}`;
        const response = await fetch(url, {
            headers: { 'x-api-key': this.apiKey, 'x-secret-key': this.secretKey, 'Content-Type': 'application/json' }
        });
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        return await response.json();
    }

    async testConnection() {
        return await this.makeRequest('/api/v4/futures/usdt/accounts');
    }

    async getTradeHistory(settle = 'usdt') {
        console.log('📈 Obteniendo historial Gate.io...');
        const data = await this.makeRequest(`/api/v4/futures/${settle}/my_trades`, { limit: 1000 });
        const trades = Array.isArray(data) ? data : [];
        console.log(`📊 Gate.io: ${trades.length} trades`);
        return trades;
    }
}

// ============================================
// PHEMEX API CLASS
// ============================================
class PhemexAPI {
    constructor(apiKey, secretKey) {
        this.apiKey = apiKey;
        this.secretKey = secretKey;
        const isProduction = window.location.hostname !== 'localhost' && window.location.hostname !== '127.0.0.1';
        this.proxyURL = isProduction ? `${window.location.origin}/api` : 'http://127.0.0.1:8003';
        console.log('🔗 Phemex API inicializada');
    }

    async makeRequest(endpoint, params = {}) {
        const queryString = new URLSearchParams(params).toString();
        const url = `${this.proxyURL}/phemex${endpoint}${queryString ? '?' + queryString : ''}`;
        const response = await fetch(url, {
            headers: { 'x-api-key': this.apiKey, 'x-secret-key': this.secretKey, 'Content-Type': 'application/json' }
        });
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        const data = await response.json();
        if (data.code !== undefined && data.code !== 0) throw new Error(`Phemex Error ${data.code}: ${data.msg || ''}`);
        return data;
    }

    async testConnection() {
        return await this.makeRequest('/g-accounts/accountPositions', { currency: 'USD' });
    }

    async getTradeHistory(symbol = '') {
        const allTrades = [];
        let offset = 0;
        const limit = 200;
        console.log('📈 Obteniendo historial Phemex...');
        for (let i = 0; i < 20; i++) {
            const params = { limit, offset };
            if (symbol) params.symbol = symbol;
            try {
                const result = await this.makeRequest('/phemex-user/order/list/closed', params);
                const trades = result.data?.rows || [];
                allTrades.push(...trades);
                if (trades.length < limit) break;
                offset += limit;
            } catch (e) { console.warn('Phemex error:', e.message); break; }
        }
        console.log(`📊 Phemex: ${allTrades.length} trades`);
        return allTrades;
    }
}

// ============================================
// BITMART FUTURES API CLASS
// ============================================
class BitmartAPI {
    constructor(apiKey, secretKey, memo) {
        this.apiKey = apiKey;
        this.secretKey = secretKey;
        this.memo = memo || '';
        const isProduction = window.location.hostname !== 'localhost' && window.location.hostname !== '127.0.0.1';
        this.proxyURL = isProduction ? `${window.location.origin}/api` : 'http://127.0.0.1:8003';
        console.log('🔗 Bitmart API inicializada');
    }

    async makeRequest(endpoint, params = {}) {
        const queryString = new URLSearchParams(params).toString();
        const url = `${this.proxyURL}/bitmart${endpoint}${queryString ? '?' + queryString : ''}`;
        const response = await fetch(url, {
            headers: { 'x-api-key': this.apiKey, 'x-secret-key': this.secretKey, 'x-passphrase': this.memo, 'Content-Type': 'application/json' }
        });
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        const data = await response.json();
        if (data.code && data.code !== 1000) throw new Error(`Bitmart Error ${data.code}: ${data.message || ''}`);
        return data;
    }

    async testConnection() {
        return await this.makeRequest('/contract/private/assets-detail');
    }

    async getTradeHistory(symbol = '') {
        const allTrades = [];
        const windowMs = 7 * 24 * 60 * 60 * 1000;
        const totalMs = 90 * 24 * 60 * 60 * 1000;
        const now = Date.now();
        let winEnd = now;
        let winStart = Math.max(winEnd - windowMs, now - totalMs);
        console.log('📈 Obteniendo historial Bitmart...');
        while (winEnd > now - totalMs && allTrades.length < 2000) {
            const params = { start_time: Math.floor(winStart / 1000), end_time: Math.floor(winEnd / 1000) };
            if (symbol) params.symbol = symbol;
            try {
                const result = await this.makeRequest('/contract/private/trades', params);
                const trades = result.data?.list || [];
                if (trades.length > 0) allTrades.push(...trades);
                else break;
            } catch (e) { console.warn('Bitmart window error:', e.message); break; }
            winEnd = winStart;
            winStart = Math.max(winEnd - windowMs, now - totalMs);
        }
        console.log(`📊 Bitmart: ${allTrades.length} trades`);
        return allTrades;
    }
}

