// Convertir trade de Bitunix al formato de la aplicación
function convertBitunixTradeToAppFormat(bitunixTrade, accountId) {
    console.log('🔄 Convirtiendo trade Bitunix:', bitunixTrade);
    
    const pnl = parseFloat(bitunixTrade.profit || bitunixTrade.pnl || 0);
    const result = pnl > 0 ? 'win' : (pnl < 0 ? 'loss' : 'breakeven');

    const tradeDateObj = new Date(parseInt(bitunixTrade.time || bitunixTrade.timestamp || Date.now()));
    const tradeDate = getLocalDateString(tradeDateObj);
    const entryTime = tradeDateObj.toTimeString().split(' ')[0];
    const exitTime = bitunixTrade.closeTime ? 
        new Date(parseInt(bitunixTrade.closeTime)).toTimeString().split(' ')[0] : entryTime;

    const tradeId = bitunixTrade.id || bitunixTrade.tradeId || Date.now();

    const converted = {
        id: `bitunix_${tradeId}`,
        date: tradeDate,
        accountId: accountId,
        instrument: bitunixTrade.symbol,
        type: (bitunixTrade.side || '').toLowerCase(),
        entry: parseFloat(bitunixTrade.price || 0),
        exit: parseFloat(bitunixTrade.price || 0),
        entryTime: entryTime,
        exitTime: exitTime,
        volume: parseFloat(bitunixTrade.amount || bitunixTrade.qty || 0),
        result: result,
        pl: pnl,
        fees: Math.abs(parseFloat(bitunixTrade.fee || 0)),
        currency: bitunixTrade.feeCurrency || 'USDT',
        notes: `Importado de Bitunix - Trade ID: ${tradeId}`,
        imageDatas: [],
        manualPL: null,
        session: detectTradingSession(entryTime) || ''
    };
    
    console.log('✅ Trade Bitunix convertido:', converted);
    return converted;
}

