async function syncBitunixTrades() {
    // 1. Verificar si hay credenciales guardadas en Supabase
    if (!bitunixAPI && currentUser) {
        console.log('🔄 bitunixAPI no inicializada, cargando credenciales desde Supabase...');
        const savedCreds = await loadBitunixCredentialsFromSupabase();
        
        if (savedCreds && savedCreds.key && savedCreds.secret) {
            console.log('✅ Credenciales encontradas, inicializando bitunixAPI...');
            bitunixAPI = new BitunixAPI(savedCreds.key, savedCreds.secret);
        }
    }

    // 2. Si aún no hay API, mostrar error
    if (!bitunixAPI) {
        showSyncNotification('❌ Primero debes configurar y guardar tus credenciales de Bitunix', 'error');
        return;
    }

    let selectedAccount = null;
    const accountDetailSelect = document.getElementById('bitunix-account-detail');
    if (accountDetailSelect && accountDetailSelect.value) {
        selectedAccount = DB.accounts.find(acc => acc.id === accountDetailSelect.value);
    }

    // Fallback: buscar o crear cuenta Bitunix automáticamente
    if (!selectedAccount) {
        selectedAccount = DB.accounts.find(acc => acc.platform === 'bitunix');
    }
    if (!selectedAccount) {
        selectedAccount = {
            id: generateId(),
            name: 'Bitunix - Cuenta Principal',
            currency: 'USDT',
            platform: 'bitunix',
            initialBalance: 0,
            balance: 0
        };
        DB.accounts.push(selectedAccount);
        await dexieDB.accounts.add(selectedAccount);
        if (currentUser) await saveAccountToSupabase(selectedAccount);
        console.log('✅ Cuenta Bitunix creada automáticamente:', selectedAccount.id);
        if (accountDetailSelect) {
            const opt = document.createElement('option');
            opt.value = selectedAccount.id;
            opt.textContent = selectedAccount.name;
            accountDetailSelect.appendChild(opt);
            accountDetailSelect.value = selectedAccount.id;
        }
    }

    showSyncNotification('🔄 Sincronizando trades de Bitunix...', 'info');

    try {
        console.log('📡 Obteniendo trades de Bitunix...');
        const tradesResponse = await bitunixAPI.getTradeHistory();
        const bitunixTrades = tradesResponse?.data || tradesResponse || [];
        
        if (!Array.isArray(bitunixTrades) || bitunixTrades.length === 0) {
            console.log('📊 Respuesta de Bitunix:', tradesResponse);
            showSyncNotification('ℹ️ No se encontraron trades en Bitunix', 'info');
            return;
        }

        console.log(`📊 Trades obtenidos: ${bitunixTrades.length}`);

        const existingTradeIds = new Set(
            DB.operations
                .filter(op => op.id.startsWith('bitunix_'))
                .map(op => op.id)
        );

        let newTradesCount = 0;
        const newOperations = [];

        for (const trade of bitunixTrades) {
            const convertedTrade = convertBitunixTradeToAppFormat(trade, selectedAccount.id);

            if (!existingTradeIds.has(convertedTrade.id)) {
                newOperations.push(convertedTrade);
                newTradesCount++;
            }
        }

        if (newOperations.length > 0) {
            console.log(`💾 Guardando ${newOperations.length} nuevas operaciones...`);
            
            await dexieDB.operations.bulkAdd(newOperations);
            DB.operations.push(...newOperations);

            if (currentUser) {
                for (const operation of newOperations) {
                    try {
                        await saveOperationToSupabase(operation);
                    } catch (error) {
                        console.error('Error sincronizando operación:', error);
                        addToSyncQueue(operation, 'operation');
                    }
                }
            }

            updateAccountBalances();
            refreshAllViews();
            showSyncNotification(`✅ Bitunix: ${newTradesCount} trades nuevos sincronizados`, 'success');
        } else {
            showSyncNotification('✅ Bitunix: Conectado - Sin trades nuevos', 'success');
        }

    } catch (error) {
        console.error('❌ Error sincronizando trades de Bitunix:', error);
        if (error.message.includes('403') || error.message.toLowerCase().includes('access restricted') || error.message.toLowerCase().includes('attack')) {
            showSyncNotification('❌ Bitunix: Acceso bloqueado por Cloudflare. Bitunix restringe IPs de servidores externos. Usa la importación por CSV de Bitunix como alternativa.', 'error');
        } else {
            showSyncNotification(`❌ Error Bitunix: ${error.message}`, 'error');
        }
    }
}

// Convertir trade de LBank al formato de la aplicación
function convertLBankTradeToAppFormat(lbankTrade, accountId) {
    console.log('🔄 Convirtiendo trade LBank:', lbankTrade);

    // orders_info_history.do fields:
    // order_id, symbol, create_time, finish_time, price, avg_price,
    // amount, deal_amount, status, type (buy/sell), deal_fee
    const pnl = parseFloat(lbankTrade.profit || lbankTrade.pnl || 0);
    const result = pnl > 0 ? 'win' : (pnl < 0 ? 'loss' : 'breakeven');

    const tradeDateObj = new Date(parseInt(lbankTrade.create_time || lbankTrade.time || Date.now()));
    const tradeDate = getLocalDateString(tradeDateObj);
    const entryTime = tradeDateObj.toTimeString().split(' ')[0];
    const exitTime = lbankTrade.finish_time ?
        new Date(parseInt(lbankTrade.finish_time)).toTimeString().split(' ')[0] : entryTime;

    const tradeId = lbankTrade.order_id || lbankTrade.trade_id || lbankTrade.id || Date.now();
    const fillPrice = parseFloat(lbankTrade.avg_price || lbankTrade.price || lbankTrade.deal_price || 0);
    const sideRaw = (lbankTrade.type || lbankTrade.trade_type || lbankTrade.side || '').toLowerCase();
    // LBank returns "buy_market", "sell_market", "buy", "sell" etc.
    const side = sideRaw.startsWith('buy') ? 'buy' : sideRaw.startsWith('sell') ? 'sell' : sideRaw;

    const converted = {
        id: `lbank_${tradeId}`,
        date: tradeDate,
        accountId: accountId,
        instrument: lbankTrade.symbol || '',
        type: side,
        entry: fillPrice,
        exit: fillPrice,
        entryTime: entryTime,
        exitTime: exitTime,
        volume: parseFloat(lbankTrade.deal_amount || lbankTrade.amount || 0),
        result: result,
        pl: pnl,
        fees: Math.abs(parseFloat(lbankTrade.deal_fee || lbankTrade.fee_amount || lbankTrade.fee || 0)),
        currency: lbankTrade.asset_code || 'USDT',
        notes: `Importado de LBank - Order ID: ${tradeId}`,
        imageDatas: [],
        manualPL: null,
        session: detectTradingSession(entryTime) || ''
    };

    console.log('✅ Trade LBank convertido:', converted);
    return converted;
}

