// Guardar credenciales de Bitunix en Supabase
async function saveBitunixCredentialsToSupabase(apiKey, secretKey, accountId) {
    if (!currentUser) {
        console.warn('❌ No current user - cannot save Bitunix credentials to Supabase');
        return null;
    }

    try {
        console.log('💾 [saveBitunix] Iniciando guardado en Supabase...');
        console.log('💾 [saveBitunix] User ID:', currentUser.id);
        
        // Primero obtener las settings actuales
        const { data: existingSettings, error: fetchError } = await supabase
            .from('user_settings')
            .select('settings')
            .eq('user_id', currentUser.id)
            .single();

        if (fetchError && fetchError.code !== 'PGRST116') {
            console.error('❌ [saveBitunix] Error al consultar settings:', fetchError);
        }

        let apiKeys = existingSettings?.settings?.api_keys || {};
        
        // Actualizar credenciales de Bitunix
        apiKeys.bitunix = {
            apiKey: apiKey,
            secretKey: secretKey,
            accountId: accountId,
            updatedAt: new Date().toISOString()
        };

        // Guardar o actualizar - PRESERVAR settings existentes
        const { data, error } = await supabase
            .from('user_settings')
            .upsert({
                user_id: currentUser.id,
                settings: { ...existingSettings?.settings, api_keys: apiKeys },
                updated_at: new Date().toISOString()
            }, {
                onConflict: 'user_id'
            });

        if (error) {
            console.error('❌ [saveBitunix] Error en upsert:', error);
            throw error;
        }

        console.log('✅ [saveBitunix] Credenciales Bitunix guardadas exitosamente');
        return data;
    } catch (error) {
        console.error('❌ [saveBitunix] Error en saveBitunixCredentialsToSupabase:', error);
        throw error;
    }
}

