// ═══════════════════════════════════════════════════════════════════════════════
// CSV PARSERS — Exchange-specific + Universal
// ═══════════════════════════════════════════════════════════════════════════════

/** Parse CSV text into array of row-objects by header */
function csvToObjects(text) {
    const lines = text.trim().split('\n').map(l => l.trim()).filter(l => l);
    if (lines.length < 2) return [];
    const headers = lines[0].split(',').map(h => h.replace(/^"|"$/g, '').trim());
    return lines.slice(1).map(line => {
        const vals = line.match(/(".*?"|[^,]+|(?<=,)(?=,)|^(?=,))/g) || line.split(',');
        const obj = {};
        headers.forEach((h, i) => { obj[h] = (vals[i] || '').replace(/^"|"$/g, '').trim(); });
        return obj;
    });
}

/** Show a native file picker and return the text content */
function pickTextFile(accept = '.csv,.xlsx') {
    return new Promise((resolve, reject) => {
        const input = document.createElement('input');
        input.type = 'file'; input.accept = accept;
        input.onchange = async (e) => {
            const file = e.target.files[0];
            if (!file) { reject(new Error('No file selected')); return; }
            if (file.name.endsWith('.xlsx')) {
                if (typeof XLSX !== 'undefined') {
                    const ab = await file.arrayBuffer();
                    const wb = XLSX.read(ab, { type: 'array' });
                    const ws = wb.Sheets[wb.SheetNames[0]];
                    resolve(XLSX.utils.sheet_to_csv(ws));
                } else {
                    showSyncNotification('⚠️ Para XLSX instala SheetJS', 'warning');
                    reject(new Error('XLSX library not loaded'));
                }
            } else {
                const reader = new FileReader();
                reader.onload = (ev) => resolve(ev.target.result);
                reader.onerror = reject;
                reader.readAsText(file);
            }
        };
        input.click();
    });
}

/** Generic trigger: pick file → parse → import trades */
async function triggerExchangeCSV(exchangeName, parserFn) {
    try {
        showSyncNotification(`📂 Selecciona el CSV de ${exchangeName}...`, 'info');
        const text = await pickTextFile('.csv,.xlsx');
        const trades = parserFn(text);
        if (!trades || trades.length === 0) {
            showSyncNotification(`⚠️ No se encontraron operaciones en el archivo de ${exchangeName}`, 'warning');
            return;
        }
        const accountId = DB.activeAccountId || DB.accounts[0]?.id;
        if (!accountId) { showSyncNotification('❌ Selecciona una cuenta primero', 'error'); return; }
        let saved = 0;
        for (const trade of trades) {
            trade.account_id = accountId;
            try { await saveTrade(trade); saved++; } catch(_) {}
        }
        await loadAllData(); renderDashboard();
        showSyncNotification(`✅ ${exchangeName}: ${saved} operaciones importadas`, 'success');
    } catch (err) {
        if (err.message !== 'No file selected') showSyncNotification(`❌ Error importando ${exchangeName}: ${err.message}`, 'error');
    }
}

// ─── Bybit CSV ────────────────────────────────────────────────────────────────
// Columns: Time, Symbol, Side, Exec Price, Exec Qty, Exec Value, Fee Paid, Closed P&L
function parseBybitCSV(text) {
    const rows = csvToObjects(text);
    return rows.map(r => {
        const pnl = parseFloat(r['Closed P&L'] || r['closedPnl'] || r['Realized P&L'] || 0);
        const fee = Math.abs(parseFloat(r['Fee Paid'] || r['fee'] || 0));
        const ts = r['Time'] || r['time'] || r['Create Time'];
        if (!ts) return null;
        return {
            id: `bybit_csv_${Date.now()}_${Math.random().toString(36).slice(2)}`,
            exchange: 'bybit', symbol: r['Symbol'] || r['symbol'] || 'UNKNOWN',
            side: (r['Side'] || '').toLowerCase() === 'sell' ? 'Sell' : 'Buy',
            pnl, fee,
            qty: parseFloat(r['Exec Qty'] || r['execQty'] || 0),
            price: parseFloat(r['Exec Price'] || r['execPrice'] || r['Avg Price'] || 0),
            date: new Date(ts).toISOString(), notes: 'CSV Bybit'
        };
    }).filter(Boolean);
}

