// Columns: Time, Symbol, Side, Price, Qty, Realized Profit, Commission
function parseBinanceFuturesCSV(text) {
    const rows = csvToObjects(text);
    return rows.map(r => {
        const pnl = parseFloat(r['Realized Profit'] || r['Realized PnL'] || r['realizedPnl'] || 0);
        const fee = Math.abs(parseFloat(r['Commission'] || r['commission'] || 0));
        const ts = r['Time'] || r['time'] || r['Date'];
        if (!ts) return null;
        return {
            id: `binance_csv_${Date.now()}_${Math.random().toString(36).slice(2)}`,
            exchange: 'binance', symbol: r['Symbol'] || r['symbol'] || 'UNKNOWN',
            side: (r['Side'] || '').toLowerCase() === 'sell' ? 'Sell' : 'Buy',
            pnl, fee,
            qty: parseFloat(r['Qty'] || r['qty'] || 0),
            price: parseFloat(r['Price'] || r['price'] || 0),
            date: new Date(ts).toISOString(), notes: 'CSV Binance Futures'
        };
    }).filter(Boolean);
}

