// ─── Universal CSV / XLSX ─────────────────────────────────────────────────────
async function importUniversalCSV() {
    try {
        showSyncNotification('📂 Selecciona tu archivo CSV o XLSX...', 'info');
        const text = await pickTextFile('.csv,.xlsx');
        const firstLine = text.split('\n')[0].toLowerCase();

        let parser, label;
        if (firstLine.includes('closed p&l') || firstLine.includes('exec price')) {
            parser = parseBybitCSV; label = 'Bybit';
        } else if (firstLine.includes('realized profit') || firstLine.includes('commission')) {
            parser = parseBinanceFuturesCSV; label = 'Binance Futures';
        } else if (firstLine.includes('instrument id') || firstLine.includes('avg fill')) {
            parser = parseOKXCSV; label = 'OKX';
        } else if (firstLine.includes('contract') && firstLine.includes('close price')) {
            parser = parseGateCSV; label = 'Gate.io';
        } else if (firstLine.includes('closedpnl') || (firstLine.includes('side') && firstLine.includes('date') && !firstLine.includes('create'))) {
            parser = parsePhemexCSV; label = 'Phemex';
        } else if (firstLine.includes('trade type') || (firstLine.includes('direction') && firstLine.includes('contract'))) {
            parser = parseBitmartCSV; label = 'Bitmart';
        } else {
            // Generic fallback — map best-effort column names
            parser = (t) => csvToObjects(t).map(r => {
                const pnl = parseFloat(r['PnL'] || r['P&L'] || r['Realized PnL'] || r['pnl'] || r['Profit'] || 0);
                const fee = Math.abs(parseFloat(r['Fee'] || r['fee'] || r['Commission'] || 0));
                const ts = r['Time'] || r['Date'] || r['Timestamp'] || r['Create Time'] || r['Close Time'];
                if (!ts) return null;
                return {
                    id: `universal_csv_${Date.now()}_${Math.random().toString(36).slice(2)}`,
                    exchange: 'universal',
                    symbol: r['Symbol'] || r['Contract'] || r['Instrument ID'] || 'UNKNOWN',
                    side: (r['Side'] || r['Direction'] || r['Type'] || '').toLowerCase().includes('buy') ? 'Buy' : 'Sell',
                    pnl, fee,
                    qty: parseFloat(r['Qty'] || r['Size'] || r['Amount'] || 0),
                    price: parseFloat(r['Price'] || r['Avg Price'] || r['Close Price'] || 0),
                    date: new Date(ts).toISOString(), notes: 'CSV Universal'
                };
            }).filter(Boolean);
            label = 'Universal';
        }

        const trades = parser(text);
        if (!trades?.length) { showSyncNotification('⚠️ No se encontraron operaciones en el archivo', 'warning'); return; }
        const accountId = DB.activeAccountId || DB.accounts[0]?.id;
        if (!accountId) { showSyncNotification('❌ Selecciona una cuenta primero', 'error'); return; }
        let saved = 0;
        for (const trade of trades) { trade.account_id = accountId; try { await saveTrade(trade); saved++; } catch(_) {} }
        await loadAllData(); renderDashboard();
        showSyncNotification(`✅ ${label}: ${saved} operaciones importadas`, 'success');
    } catch (err) {
        if (err.message !== 'No file selected') showSyncNotification(`❌ Universal CSV error: ${err.message}`, 'error');
    }
}

