    // Event listener for Bitunix CSV import button
    const bitunixImportCsvBtn = document.getElementById('bitunix-import-csv');
    if (bitunixImportCsvBtn) {
        bitunixImportCsvBtn.addEventListener('click', (e) => {
            e.stopPropagation();
            const input = document.createElement('input');
            input.type = 'file';
            input.accept = '.csv';
            input.style.display = 'none';
            document.body.appendChild(input);
            input.click();
            input.onchange = async (ev) => {
                const file = ev.target.files[0];
                if (!file) return;
                try {
                    const rawText = await file.text();
                    const csvText = rawText.replace(/^\uFEFF/, '');
                    const firstLine = csvText.split(/[\n\r]/)[0].toLowerCase();
                    const isNative = firstLine.includes('futures') && firstLine.includes('opening time') && firstLine.includes('realized pnl');
                    if (isNative) {
                        // Use first Bitunix account or first available account
                        const acc = DB.accounts.find(a => a.platform === 'bitunix' || (a.broker || '').toLowerCase() === 'bitunix') || DB.accounts[0];
                        if (!acc) { showSyncNotification('❌ No hay cuentas disponibles. Crea una cuenta primero.', 'error'); return; }
                        await processBitunixNativeCSV(csvText, acc.id);
                    } else {
                        showSyncNotification('⚠️ Usa el formato nativo de Bitunix (exportado desde Historial de posición)', 'warning');
                    }
                } catch (err) {
                    console.error('Error importando CSV Bitunix:', err);
                    showSyncNotification('❌ Error procesando CSV: ' + err.message, 'error');
                }
                document.body.removeChild(input);
            };
        });
    }

