    if (mexcCsvBtn) {
        // Populate account selector when CSV tab is shown
        const mexcCsvAccountSel = document.getElementById('mexc-csv-account');
        function populateMEXCCsvAccounts() {
            if (!mexcCsvAccountSel) return;
            const prevValue = mexcCsvAccountSel.value;
            mexcCsvAccountSel.innerHTML = '<option value="">Selecciona una cuenta...</option>';
            const mexcAccs = DB.accounts.filter(a => a.platform === 'mexc' || a.broker === 'MEXC' || a.broker === 'mexc');
            const list = mexcAccs.length > 0 ? mexcAccs : DB.accounts;
            list.forEach(acc => {
                const o = document.createElement('option');
                o.value = acc.id;
                o.textContent = `${acc.name} (${acc.currency})`;
                mexcCsvAccountSel.appendChild(o);
            });
            if (prevValue && mexcCsvAccountSel.querySelector(`option[value="${prevValue}"]`)) {
                mexcCsvAccountSel.value = prevValue;
            } else if (list.length > 0) {
                mexcCsvAccountSel.value = list[0].id;
            }
        }
        window.populateMEXCCsvAccounts = populateMEXCCsvAccounts;
        document.addEventListener('click', (e) => {
            if (e.target?.closest?.('[data-tab="mexc-tab-csv"]')) populateMEXCCsvAccounts();
        });

        mexcCsvBtn.addEventListener('click', async () => {
            // Read accountId FIRST — do NOT repopulate here
            const fileInput = document.getElementById('mexc-csv-file-input');
            const statusDiv = document.getElementById('mexc-csv-import-status');

            if (!fileInput.files[0]) {
                statusDiv.textContent = 'Por favor selecciona un archivo CSV o Excel (.xlsx)';
                statusDiv.className = 'text-sm text-negative';
                return;
            }

            try {
                statusDiv.textContent = 'Procesando archivo...';
                statusDiv.className = 'text-sm text-blue-400';

                const file = fileInput.files[0];
                const isXlsx = /\.xlsx?$/i.test(file.name);

                if (isXlsx) {
                    // Parse XLSX with SheetJS
                    const ab = await file.arrayBuffer();
                    const wb = XLSX.read(ab, { type: 'array' });
                    const ws = wb.Sheets[wb.SheetNames[0]];
                    const rows = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '', raw: false, dateNF: 'yyyy-mm-dd hh:mm:ss' });
                    const accountId = document.getElementById('mexc-csv-account')?.value || '';
                    await processMEXCNativeExport(rows, accountId);
                } else {
                    // CSV: auto-detect format by header
                    const csvText = await file.text();
                    const firstLine = csvText.split(/[\n\r]/)[0].toLowerCase();
                    const isNativeMEXC = firstLine.includes('uid') || firstLine.includes('tiempo') || firstLine.includes('par de') || firstLine.includes('direcci');
                    if (isNativeMEXC) {
                        // Parse CSV into rows array for the native parser
                        const rows = csvText.split(/[\n\r]+/)
                            .filter(l => l.trim())
                            .map(l => l.split(',').map(c => c.trim().replace(/^"|"$/g, '')));
                        const accountId = document.getElementById('mexc-csv-account')?.value || '';
                        await processMEXCNativeExport(rows, accountId);
                    } else {
                        await processMEXCCSV(csvText);
                    }
                }

                statusDiv.textContent = '✅ Archivo importado exitosamente';
                statusDiv.className = 'text-sm text-positive';
                fileInput.value = '';
                updateMEXCImportHistory();

            } catch (error) {
                console.error('Error procesando archivo MEXC:', error);
                statusDiv.textContent = `❌ Error: ${error.message}`;
                statusDiv.className = 'text-sm text-negative';
            }
        });
    }

