    // ─── CSV import with status feedback (detail panels) ───────────────────
    async function triggerExchangeCSVWithSelect(exchangeName, parserFn, accountSelectId, statusDivId) {
        const statusDiv = document.getElementById(statusDivId);
        try {
            if (statusDiv) { statusDiv.textContent = '📂 Seleccionando archivo...'; statusDiv.className = 'text-sm text-yellow-400'; }
            const text = await pickTextFile('.csv,.xlsx');
            const trades = parserFn(text);
            if (!trades?.length) {
                if (statusDiv) { statusDiv.textContent = '⚠️ No se encontraron operaciones en el archivo.'; statusDiv.className = 'text-sm text-yellow-400'; }
                return;
            }
            const accountId = document.getElementById(accountSelectId)?.value || DB?.activeAccountId || DB?.accounts?.[0]?.id;
            if (!accountId) { if (statusDiv) { statusDiv.textContent = '❌ Selecciona una cuenta primero.'; statusDiv.className = 'text-sm text-red-400'; } return; }
            let saved = 0;
            for (const trade of trades) { trade.account_id = accountId; try { await saveTrade(trade); saved++; } catch(_) {} }
            await loadAllData(); renderDashboard();
            if (statusDiv) { statusDiv.textContent = `✅ ${saved} operaciones importadas de ${exchangeName}.`; statusDiv.className = 'text-sm text-green-400'; }
            // Actualizar tarjeta de plataforma
            const exKey = exchangeName.toLowerCase().replace(/\s/g,'-');
            const cardLS = document.getElementById(`${exKey}-last-sync`);
            const cardPB = document.getElementById(`${exKey}-progress-bar`);
            const cardSI = document.getElementById(`${exKey}-status-indicator`);
            const now = new Date(); const sd = `${now.toLocaleDateString('es-ES')} ${now.toLocaleTimeString('es-ES')}`;
            if (cardLS) cardLS.textContent = sd;
            if (cardPB) cardPB.style.width = '100%';
            if (cardSI && !cardSI.classList.contains('platform-connected')) { cardSI.textContent = 'Manual'; cardSI.className = 'platform-connected'; }
        } catch(err) {
            if (err.message !== 'No file selected') {
                if (statusDiv) { statusDiv.textContent = `❌ Error: ${err.message}`; statusDiv.className = 'text-sm text-red-400'; }
            } else {
                if (statusDiv) { statusDiv.textContent = ''; }
            }
        }
    }

