/** Toggle API key field visibility with eye button */
window.toggleApiField = function(inputId, btn) {
    const input = document.getElementById(inputId);
    if (!input) return;
    const isHidden = input.type === 'password';
    input.type = isHidden ? 'text' : 'password';
    const icon = btn ? btn.querySelector('i') : null;
    if (icon) { icon.className = isHidden ? 'fas fa-eye-slash' : 'fas fa-eye'; }
};

/** Populate an account select for a new exchange */
function populateNewExchangeAccountSelect(selectId, exchangeName) {
    const sel = document.getElementById(selectId);
    if (!sel || !DB?.accounts) return;
    const current = sel.value;
    sel.innerHTML = '<option value="">Seleccionar cuenta...</option>';
    DB.accounts.forEach(acc => {
        const opt = document.createElement('option');
        opt.value = acc.id;
        opt.textContent = acc.name || acc.id;
        sel.appendChild(opt);
    });
    if (current) sel.value = current;
}

/** Generic helper: save new-exchange credentials and instantiate API class */
async function saveNewExchangeCredentials(exchange, fields, accountSelectId) {
    const credObj = {};
    let valid = true;
    for (const [key, id] of Object.entries(fields)) {
        const el = document.getElementById(id);
        if (!el || !el.value.trim()) {
            if (key !== 'passphrase' && key !== 'memo') { valid = false; break; }
        }
        credObj[key] = el ? el.value.trim() : '';
    }
    if (!valid) { showSyncNotification(`❌ Introduce la API Key y Secret Key de ${exchange}`, 'error'); return false; }
    const accountId = document.getElementById(accountSelectId)?.value || DB?.accounts?.[0]?.id || '';
    credObj.accountId = accountId;
    try {
        await saveExchangeCredentials(exchange, credObj);
        // Instantiate the API class
        if (exchange === 'bybit') bybitAPI = new BybitAPI(credObj.apiKey, credObj.secretKey);
        else if (exchange === 'binance') binanceFuturesAPI = new BinanceFuturesAPI(credObj.apiKey, credObj.secretKey);
        else if (exchange === 'okx') okxAPI = new OKXAPI(credObj.apiKey, credObj.secretKey, credObj.passphrase || '');
        else if (exchange === 'gate') gateAPI = new GateAPI(credObj.apiKey, credObj.secretKey);
        else if (exchange === 'phemex') phemexAPI = new PhemexAPI(credObj.apiKey, credObj.secretKey);
        else if (exchange === 'bitmart') bitmartAPI = new BitmartAPI(credObj.apiKey, credObj.secretKey, credObj.memo || '');
        // Update status indicator on card
        const si = document.getElementById(`${exchange}-status-indicator`);
        if (si) { si.textContent = 'Conectado'; si.className = 'platform-connected'; }
        const pb = document.getElementById(`${exchange}-progress-bar`);
        if (pb) pb.style.width = '100%';
        const cs = document.getElementById(`${exchange}-connection-status`);
        if (cs) { cs.className = 'status-card status-card-success mb-6'; cs.innerHTML = '<i class="fas fa-check-circle status-card-icon"></i><div><p class="font-semibold text-lg mb-1">Conectado</p><p class="text-sm opacity-90">Credenciales guardadas correctamente.</p></div>'; }
        showSyncNotification(`✅ Credenciales de ${exchange} guardadas`, 'success');
        return true;
    } catch(err) {
        showSyncNotification(`❌ Error guardando credenciales de ${exchange}: ${err.message}`, 'error');
        return false;
    }
}

/** Generic test connection for new exchanges */
async function testNewExchangeConnection(exchange, apiInstance, testEndpointFn) {
    if (!apiInstance) { showSyncNotification(`❌ Primero guarda las credenciales de ${exchange}`, 'error'); return; }
    showSyncNotification(`🔌 Probando conexión con ${exchange}...`, 'info');
    try {
        await testEndpointFn(apiInstance);
        showSyncNotification(`✅ Conexión con ${exchange} exitosa`, 'success');
    } catch(err) {
        showSyncNotification(`❌ Error de conexión con ${exchange}: ${err.message}`, 'error');
    }
}

function syncBingXData() {
    // Sincronizar claves API
    const apiKey = document.getElementById('bingx-api-key')?.value || '';
    const secretKey = document.getElementById('bingx-api-secret')?.value || '';
    const selectedAccount = document.getElementById('bingx-account')?.value || '';

    if (document.getElementById('bingx-api-key-detail')) {
        document.getElementById('bingx-api-key-detail').value = apiKey;
    }
    if (document.getElementById('bingx-secret-key-detail')) {
        document.getElementById('bingx-secret-key-detail').value = secretKey;
    }
    if (document.getElementById('bingx-account-detail')) {
        document.getElementById('bingx-account-detail').value = selectedAccount;
    }
}

function updateBingXDetailStatus() {
    const statusElement = document.getElementById('bingx-connection-status');
    const proxyElement = document.getElementById('bingx-proxy-status-detail');

    // Verificar si hay credenciales guardadas
    const hasLocalCredentials = localStorage.getItem('bingx-api-key') && localStorage.getItem('bingx-secret-key');
    const hasDbCredentials = (typeof window.DB !== 'undefined' && window.DB.apiKeys && window.DB.apiKeys.bingx) 
        ? (window.DB.apiKeys.bingx.key && window.DB.apiKeys.bingx.secret) 
        : false;

    if ((bingxAPI && bingxAPI.apiKey) || hasLocalCredentials || hasDbCredentials) {
        // Conectado (banner oculto por CSS)

        // Actualizar indicadores en la tarjeta de plataforma
        const statusIndicator = document.getElementById('bingx-status-indicator');
        const progressBar = document.getElementById('bingx-progress-bar');

        if (statusIndicator) {
            statusIndicator.textContent = 'Conectado';
            statusIndicator.className = 'platform-connected';
        }
        if (progressBar) {
            progressBar.style.width = '100%';
        }

        // Mostrar botones de sincronización
        const syncBtn = document.getElementById('bingx-sync');
        if (syncBtn) syncBtn.style.display = 'inline-block';

    } else {
        // No conectado
        // Not connected (banner is hidden)

        // Actualizar indicadores en la tarjeta de plataforma
        const statusIndicator = document.getElementById('bingx-status-indicator');
        const progressBar = document.getElementById('bingx-progress-bar');

        if (statusIndicator) {
            statusIndicator.textContent = 'No conectado';
            statusIndicator.className = 'text-yellow-400';
        }
        if (progressBar) {
            progressBar.style.width = '0%';
        }

        // Ocultar botón de sincronización
        const syncBtn = document.getElementById('bingx-sync');
        if (syncBtn) syncBtn.style.display = 'none';
    }
}

