                // Cripto Futuros
                'BTC': 'CME:BTC1!',
                'MBT': 'CME:MBT1!',
                'ETH': 'CME:ETH1!',
                'MET': 'CME:MET1!',
                
                // Bonos y Tasas
                'ZN': 'CBOT:ZN1!',
